/* ===============================================================
   n8n Function node – Rapport quotidien MLC / MATA (HTML e-mail)
   (Version SANS régression + AJOUTS demandés)

   ✅ AJOUT : Mapping « Virement » (depuis JSON / node VIREMENT_NODE)
   ✅ AJOUT : Colonne « Virement » dans le HTML
   ✅ AJOUT : Calcul Breaks inclut le montant du virement
   ✅ AJOUT : Points de vente NON case sensitive (tri + créance + virement + status + MLC)
   ✅ AJOUT : Colonne « Vente CD Exécutée » (ventesSaisiesRecuesParCentreDecoupe)
   ✅ NOTE  : L'API renvoie désormais directement
              ecart     = ventesTheoriques − (ventesSaisies + ventesSaisiesRecuesParCentreDecoupe)
              ecartCash = cashPayments     − (ventesSaisies + ventesSaisiesRecuesParCentreDecoupe)
              → aucune soustraction supplémentaire côté Function node.
   ✅ AJOUT : Break = Écart Cash + Delta Créance + Virement
   =============================================================== */

/* ------------------------------------------------------------------ 
 *                    Configuration / constantes                      
 * ------------------------------------------------------------------ */
const CREANCE_NODE = 'Get Creance MataBanq';
const ANALYTICS_NODE = 'Get analytics';
const MLC_NODE = 'mlc'; // Node pour les données MLC
const PV_STATUS_NODE = 'point de vente status'; // sentiments par PV

// === NOUVEAU : Node n8n pour les virements ===
const VIREMENT_NODE = 'Get Virement MataBanq';

const DIAG = false;
const ALERT_ECART_PCT = 10;
const ALERT_ECART_CASH = 10_000;

// Tolérance pour considérer (Écart Cash + Delta Créance + Virement) comme « No Break »
const BREAK_TOLERANCE = 1; // FCFA

const REC_NODES = ['Get Rec from matix','Get Rec from matix node','Get Rec matix','Get Rec'];
const PRODUCT_FILTER = new Set(['Poulet','Tablette']);

/* ------------------------------------------------------------------ 
 *                      Helpers génériques                            
 * ------------------------------------------------------------------ */
function esc(s){return String(s ?? '').replace(/[&<>"']/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]));}
function formatCurrency(v){const n=Number(v)||0;return `${n.toLocaleString('fr-FR')} FCFA`;}
function formatNumber(v){return Number(v||0).toLocaleString('fr-FR');}

function toNumber(val){
  if(val==null||val==='')return 0;
  if(typeof val==='number')return Number.isFinite(val)?val:0;
  if(typeof val==='string'){
    const s=val.replace(/\s/g,'').replace(/,/g,'.').replace(/[^\d.-]/g,'');
    const n=Number(s);
    return Number.isFinite(n)?n:0;
  }
  const n=Number(val);
  return Number.isFinite(n)?n:0;
}

function pct(a,b){a=toNumber(a);b=toNumber(b);return b>0? (a/b)*100 : 0;} // Pourcentage générique

function normalizeDateStr(s){
  if(!s)return'';
  if(s instanceof Date && !isNaN(s))return s.toISOString().slice(0,10);
  if(typeof s!=='string'){const d=new Date(s);return isNaN(d)?'':d.toISOString().slice(0,10);}
  const t=s.trim();
  if(/^\d{4}-\d{2}-\d{2}T/.test(t))return t.slice(0,10);
  if(/^\d{4}-\d{2}-\d{2}$/.test(t))return t;
  if(/^\d{2}-\d{2}-\d{4}$/.test(t)){const [jj,mm,aaaa]=t.split('-');return `${aaaa}-${mm}-${jj}`;}
  if(/^\d{4}\/\d{2}\/\d{2}$/.test(t))return t.replace(/\//g,'-');
  if(/^\d{2}\/\d{2}\/\d{4}$/.test(t)){const [jj,mm,aaaa]=t.split('/');return `${aaaa}-${mm}-${jj}`;}
  const d=new Date(t);return isNaN(d)?'':d.toISOString().slice(0,10);
}

function extractTimeStr(s){
  if(!s)return '';
  const str=String(s);
  const m=str.match(/T(\d{2}:\d{2})(?::\d{2})?/);
  return m?m[1]:'';
}

function safeItems(nodeName){try{return (typeof $items==='function')?($items(nodeName)||[]):[]}catch{return[]}}

function pctStr(x){const n=toNumber(x);return `${n.toFixed(2)} %`;}

function spanAmount(v){
  const n=toNumber(v);
  const color=n<0?'#C0392B':(n>0?'#1E8449':'#2C3E50');const fw=n!==0?'600':'500';
  return `<span style="color:${color};font-weight:${fw}">${formatCurrency(n)}</span>`;
}

function spanPercent(v){
  if(v==null||!isFinite(v))return '';
  const n=toNumber(v);
  const color=n<0?'#C0392B':(n>0?'#1E8449':'#2C3E50');
  const fw=n!==0?'600':'500';
  return `<span style="color:${color};font-weight:${fw}">${n.toFixed(2)} %</span>`;
}

function chip(text,type='info'){
  const p={info:{bg:'#EEF2FF',color:'#1E40AF',br:'#C7D2FE'},ok:{bg:'#E8F5E9',color:'#1B5E20',br:'#A5D6A7'},warn:{bg:'#FFF8E1',color:'#8D6E00',br:'#FFE082'},danger:{bg:'#FFEBEE',color:'#B71C1C',br:'#EF9A9A'}}[type]||{bg:'#EEE',color:'#333',br:'#DDD'};
  return `<span style="display:inline-block;padding:2px 8px;border:1px solid ${p.br};border-radius:999px;background:${p.bg};color:${p.color};font-size:12px;line-height:18px;">${esc(text)}</span>`;
}

function normProd(s){return String(s||'').normalize('NFD').replace(/[\u0300-\u036f]/g,'').trim().toLowerCase();}
function keepProduct(name){const n=normProd(name);return (PRODUCT_FILTER.has('Poulet')&&n==='poulet')||(PRODUCT_FILTER.has('Tablette')&&n==='tablette');}

function deepFindAmount(x){
  if(x==null)return null;
  if(typeof x==='number')return x;
  if(typeof x==='object'){
    if(Object.prototype.hasOwnProperty.call(x,'amount'))return x.amount;
    if(Array.isArray(x)){for(const e of x){const r=deepFindAmount(e);if(r!=null)return r}}
    else{for(const k of Object.keys(x)){const r=deepFindAmount(x[k]);if(r!=null)return r}}
  }
  return null;
}

function readNodeAmount(nodeName){
  const arr=safeItems(nodeName);
  for(const it of arr){
    let j=it?.json;
    if(!j)continue;
    if(typeof j==='string'){try{j=JSON.parse(j)}catch{}}
    const v=deepFindAmount(j);
    if(v!=null)return toNumber(v);
  }
  return 0;
}

function toPlainText(x){
  if(x==null)return'';
  if(Array.isArray(x))return x.map(v=>String(v??'')).filter(Boolean).join(' • ');
  if(typeof x==='object'){try{return Object.values(x).map(v=>String(v??'')).filter(Boolean).join(' • ')}catch{return String(x)}}
  return String(x);
}

function truncate(s,max=220){s=String(s||'');return s.length>max?s.slice(0,max-1)+'…':s;}
function getResumeComment(res){const raw=res?.commentaire??res?.comment??res?.comments??res?.note??res?.remark??'';return truncate(toPlainText(raw),220);}
function shouldHideCommentForAbattage(text){return /stock matin nul\s*-\s*calcul impossible/i.test(String(text||''));}

/* ------------------------------------------------------------------ 
 *          NORMALISATION PV (non case sensitive + accents)            
 * ------------------------------------------------------------------ */
function normalizePvLabel(s){
  return String(s||'')
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g,'')
    .trim()
    .toLowerCase();
}
function pvKey(s){ return normalizePvLabel(s); }

/* ------------------------------------------------------------------ 
 *                   Extraction données MLC                           
 * ------------------------------------------------------------------ */
function extractMlcData(){
  const arr = safeItems(MLC_NODE);
  if(arr.length === 0) return null;

  for(const it of arr){
    let j = it?.json;
    if(!j) continue;
    if(typeof j === 'string'){
      try{ j = JSON.parse(j); }catch{}
    }

    // Si c'est un tableau, prendre le premier élément
    if(Array.isArray(j) && j.length > 0){
      j = j[0];
    }

    if(j?.summary){
      return {
        panierMoyen: toNumber(j.summary?.courses_mata?.panier_moyen),
        panierTotalJour: toNumber(j.summary?.courses_mata?.panier_total_jour),
        nombreCommandes: toNumber(j.summary?.courses_mata?.total),
        sentimentGlobal: j.summary?.courses_mata?.sentimentAnalysis || null,
        parPointVente: Array.isArray(j.summary?.courses_mata?.par_point_vente) 
          ? j.summary.courses_mata.par_point_vente 
          : []
      };
    }
  }
  return null;
}

function getMlcSentimentForPv(mlcData, pvName){
  if(!mlcData || !Array.isArray(mlcData.parPointVente)) return null;
  const targetPv = pvKey(pvName);
  for(const pv of mlcData.parPointVente){
    const pvNorm = pvKey(pv.point_de_vente || '');
    if(pvNorm === targetPv){
      return pv.sentimentAnalysis || null;
    }
  }
  return null;
}

/* ------------------------------------------------------------------ 
 *            PV Status (responsable & clients)  
 * ------------------------------------------------------------------ */
function extractPvStatusData(){
  const out = new Map();
  const arr = safeItems(PV_STATUS_NODE);
  for(const it of arr){
    let j = it?.json;
    if(!j) continue;
    if(typeof j === 'string'){ try{ j = JSON.parse(j); } catch{} }

    let parentDate = null;
    let entries = [];

    // Cas: j.data = { "YYYY-MM-DD": [ {point_de_vente, sentiment_analysis, client_sentiment_analysis}, ... ] }
    if(j?.data && typeof j.data === 'object' && !Array.isArray(j.data)){
      const keys = Object.keys(j.data)
        .filter(k=>/^\d{4}-\d{2}-\d{2}$/.test(k))
        .sort().reverse(); // prend la plus récente
      if(keys.length){
        parentDate = keys[0];
        entries = Array.isArray(j.data[parentDate]) ? j.data[parentDate] : [];
      }
    } else if(Array.isArray(j)) {
      // Fallback: tableau plat
      entries = j;
      parentDate = normalizeDateStr(j?.period?.end || j?.period?.start || j?.date);
    } else if(j?.entries && Array.isArray(j.entries)){
      entries = j.entries;
      parentDate = normalizeDateStr(j?.date || j?.period?.end || j?.period?.start);
    }

    const pDate = normalizeDateStr(j?.period?.end || j?.period?.start || parentDate);

    for(const row of entries){
      const pv = row.point_de_vente || row.pointVente || row.pdv || row.PointDeVente;
      if(!pv) continue;
      const key = pvKey(pv);

      const status = row.sentiment_analysis || row.responsable_sentiment || {};
      const client = row.client_sentiment_analysis || row.clients_sentiment || {};

      out.set(key, {
        parentDate: pDate || '',
        statusSummary: (status && (status.summary || status.resume || status.text)) ? (status.summary || status.resume || status.text) : '',
        statusSentiment: status.sentiment || status.label || '',
        statusScore: toNumber(status.score),

        clientSummary: (client && (client.summary || client.resume || client.text)) ? (client.summary || client.resume || client.text) : '',
        clientSentiment: client.sentiment || client.label || '',
        clientScore: toNumber(client.score),
        clientDate: normalizeDateStr(client.latest_date || client.date || client.date_analyse)
      });
    }
  }
  return out;
}

function getPvStatusForPv(map, pvName){
  if(!map) return null;
  return map.get(pvKey(pvName)) || null;
}

/* ------------------------------------------------------------------ 
 *                 NOUVEAU : Virements (mapping PV)                    
 * ------------------------------------------------------------------ */
function collectVirementPayloads(){
  const payloads = [];

  // 1) Si le JSON est injecté directement dans le Function node
  if(typeof items !== 'undefined' && items && Array.isArray(items)){
    for(const it of items){
      let j = it?.json;
      if(!j) continue;
      if(typeof j === 'string'){ try{ j = JSON.parse(j); }catch{} }
      if(j) payloads.push(j);
      if(j?.data) payloads.push(j.data);
    }
  }

  // 2) Depuis le node dédié
  const arr = safeItems(VIREMENT_NODE);
  for(const it of arr){
    let j = it?.json;
    if(!j) continue;
    if(typeof j === 'string'){ try{ j = JSON.parse(j); }catch{ continue; } }
    payloads.push(j);
    if(j?.data) payloads.push(j.data);
  }

  return payloads;
}

/**
 * Retourne une Map(pvKey => montantVirement) pour la date sélectionnée si possible.
 * Supporte plusieurs formats potentiels :
 * - root.data["YYYY-MM-DD"] = [{pointDevente, montant/total_virement,...}]
 * - root.virements_par_point_vente = [...]
 * - root.virements_par_client = [...] (agrège par pointDevente)
 */
function extractVirementMap(selectedDateNorm){
  const out = new Map();
  const payloads = collectVirementPayloads();

  function add(pv, amount){
    const k = pvKey(pv);
    if(!k) return;
    out.set(k, toNumber(out.get(k)) + toNumber(amount));
  }

  for(let p of payloads){
    if(Array.isArray(p) && p.length) p = p[0];

    // 1) Cas data[date]
    if(p?.data && typeof p.data === 'object' && !Array.isArray(p.data)){
      const keys = Object.keys(p.data).filter(k=>/^\d{4}-\d{2}-\d{2}$/.test(k)).sort().reverse();
      const useKey = (selectedDateNorm && p.data[selectedDateNorm]) ? selectedDateNorm : (keys[0] || null);
      const rows = useKey && Array.isArray(p.data[useKey]) ? p.data[useKey] : [];
      for(const r of rows){
        const pv = r.pointDevente || r.point_de_vente || r.pointVente || r.pdv || r.PointDeVente || r.point_de_vente_nom;
        const amt = r.montant ?? r.amount ?? r.total_virement ?? r.total_amount ?? r.total ?? r.somme ?? 0;
        const d = normalizeDateStr(r.date || r.date_operation || r.operation_date || r.timestamp || r.derniere_date);
        if(selectedDateNorm && d && d !== selectedDateNorm) continue;
        if(pv) add(pv, amt);
      }
      continue;
    }

    // 2) Cas virements_par_point_vente
    if(Array.isArray(p?.virements_par_point_vente)){
      for(const r of p.virements_par_point_vente){
        const pv = r.pointDevente || r.point_de_vente || r.pointVente || r.pdv || r.PointDeVente || r.point_de_vente_nom;
        const amt = r.montant ?? r.amount ?? r.total_virement ?? r.total_amount ?? r.total ?? r.somme ?? 0;
        const d = normalizeDateStr(r.date || r.date_operation || r.operation_date || r.timestamp || r.derniere_date);
        if(selectedDateNorm && d && d !== selectedDateNorm) continue;
        if(pv) add(pv, amt);
      }
      continue;
    }

    // 3) Cas virements_par_client (agrège par PV)
    if(Array.isArray(p?.virements_par_client)){
      for(const r of p.virements_par_client){
        const pv = r.pointDevente || r.point_de_vente || r.pointVente || r.pdv || r.PointDeVente || r.point_de_vente_nom;
        const amt = r.montant ?? r.amount ?? r.total_virement ?? r.total_amount ?? r.total ?? r.somme ?? 0;
        const d = normalizeDateStr(r.date || r.date_operation || r.operation_date || r.timestamp || r.derniere_date);
        // si une date ligne existe et qu’on a une date sélectionnée, on filtre
        if(selectedDateNorm && d && d !== selectedDateNorm) continue;
        if(pv) add(pv, amt);
      }
      continue;
    }

    // 4) Cas tableau plat
    if(Array.isArray(p)){
      for(const r of p){
        const pv = r.pointDevente || r.point_de_vente || r.pointVente || r.pdv || r.PointDeVente || r.point_de_vente_nom;
        const amt = r.montant ?? r.amount ?? r.total_virement ?? r.total_amount ?? r.total ?? r.somme ?? 0;
        const d = normalizeDateStr(r.date || r.date_operation || r.operation_date || r.timestamp || r.derniere_date);
        if(selectedDateNorm && d && d !== selectedDateNorm) continue;
        if(pv) add(pv, amt);
      }
    }
  }

  return out;
}

function getVirementForPv(vMap, pvName){
  if(!vMap) return 0;
  return toNumber(vMap.get(pvKey(pvName)) || 0);
}

/* ------------------------------------------------------------------ 
 *              Perrations (kg) — Bœuf / Veau / Agneau                
 * ------------------------------------------------------------------ */
function getPVProduct(details, pvName, prodName){
  const pv = details?.[pvName] || null;
  if(!pv) return null;
  return pv[prodName] || null;
}

function computePerrationKg(pvName, prodName, details){
  const d = getPVProduct(details, pvName, prodName);
  if(!d) return null;

  const isCF = pvKey(pvName) === pvKey('chambre froide');
  const isAbattage = pvKey(pvName) === pvKey('abattage');
  if(isAbattage) return null;

  const pn = (x)=>toNumber(d?.[x]);

  if(isCF){
    const transf = Math.abs(pn('transfertsNombre'));
    const denom = Math.abs(pn('stockMatinNombre') - pn('stockSoirNombre'));
    if(!(transf>0) || !(denom>0)) return null;
    const pct = (transf/denom) - 1;
    return { soldKg:null, theoKg:null, deltaKg:null, pct };
  }

  const ventesNombreAjustePack = pn('ventesNombreAjustePack');
  const ventesTheoNombre = pn('ventesTheoriquesNombre');
  const ventesValeur = pn('ventesValeur');
  const ventesTheoValeur = pn('ventesTheoriquesValeur');
  const pu = pn('stockMatinPrixUnitaire');

  let soldKg = null, theoKg = null;
  if(ventesNombreAjustePack>0 && ventesTheoNombre>0){
    soldKg = ventesNombreAjustePack;
    theoKg = ventesTheoNombre;
  } else if(ventesValeur>0 && pu>0 && ventesTheoValeur>0){
    soldKg = ventesValeur / pu;
    theoKg = ventesTheoValeur / pu;
  }

  if(!(soldKg>0) || !(theoKg>0)) return null;

  const deltaKg = soldKg - theoKg;
  const pct = (soldKg/theoKg) - 1;

  return { soldKg, theoKg, deltaKg, pct };
}

/* ------------------------------------------------------------------ 
 *            Détection des Packs par point de vente                  
 * ------------------------------------------------------------------ */
function collectPackSales(details={}, pvName){
  const pv = details?.[pvName] || null;
  if(!pv) return [];

  const out = [];
  for(const [k,v] of Object.entries(pv)){
    if(/^pack/i.test(String(k))){
      const vs = toNumber(v?.ventesSaisies ?? v?.ventesValeur);
      const vn = toNumber(v?.ventesNombreAjustePack);
      if(vs>0 || vn>0){
        out.push({name:k, vs, vn});
      }
    }
  }
  out.sort((a,b)=>b.vs - a.vs);
  return out;
}

/* ------------------------------------------------------------------ 
 *              Totaux globaux (résumé du jour)                       
 * ------------------------------------------------------------------ */
function computeGlobalTotals(resumes=[]){
  return (Array.isArray(resumes)?resumes:[]).reduce((acc,r)=>{
    const vs=toNumber(r.ventesSaisies);
    const vt=toNumber(r.ventesTheoriques);
    const cp=toNumber(r.cashPayments);
    // ✅ r.ecart et r.ecartCash sont déjà ajustés côté API (intègrent venteCD)
    const ec=toNumber(r.ecart);
    const ecc=toNumber(r.ecartCash);
    const isAbattage = pvKey(r.pointVente||'') === pvKey('abattage');

    acc.venteJour+=vs;
    acc.cashJour+=cp;
    if(!isAbattage){acc.venteTheoJour+=vt;acc.ecartJourHorsAb+=ec;}
    else{acc.ecartAbattage+=ec;}
    acc.ecartCashJour+=ecc;
    return acc;
  },{venteJour:0,venteTheoJour:0,cashJour:0,ecartJourHorsAb:0,ecartAbattage:0,ecartCashJour:0});
}

function computeAbattageSplit(details={}, volumeB=0, volumeV=0){
  const ab=details?.Abattage||{};
  const tB=toNumber(ab?.Boeuf?.transfertsNombre);
  const tV=toNumber(ab?.Veau?.transfertsNombre);
  const pctB=(tB>0&&volumeB>0)?(tB/volumeB)*100:0;
  const pctV=(tV>0&&volumeV>0)?(tV/volumeV)*100:0;
  return{boeuf:{amount:tB,pct:pctB,volRef:volumeB},veau:{amount:tV,pct:pctV,volRef:volumeV}};
}

/* ------------------------------------------------------------------ 
 *                Créances : collecte / extraction                    
 * ------------------------------------------------------------------ */
function buildCreanceMapFromCode1(){
  const map=new Map();let fallbackDate=null;
  const code1Items=safeItems('Code1');const rows=[];
  for(const it of code1Items){
    const j0=it?.json;if(!j0)continue;let j=j0;
    if(typeof j==='string'){try{j=JSON.parse(j)}catch{}}
    if(Array.isArray(j))rows.push(...j);
    else if(Array.isArray(j.data))rows.push(...j.data);
    else rows.push(j);
  }
  for(const row of rows){
    const pvRaw=row.pointVente??row['Point de Vente']??row.point_vente??row.pv;
    const d=row.date??row.Date??null;
    if(!pvRaw&&d&&row.differenceCreance==null){fallbackDate=d;continue;}
    if(!pvRaw)continue;
    const pv=String(pvRaw).trim();
    const diff=toNumber(row.differenceCreance);
    map.set(pvKey(pv),{diff,date:d||fallbackDate||''});
  }
  return map;
}

function collectCreancePayloads(){
  const payloads=[];
  if(typeof items !== 'undefined' && items && Array.isArray(items)){
    for(const it of items){
      let j=it?.json;
      if(!j)continue;
      if(typeof j==='string'){try{j=JSON.parse(j)}catch{}}
      if(j?.summary&&(Array.isArray(j?.details)||j?.summary?.totals))payloads.push(j);
      if(j?.data?.summary&&(Array.isArray(j?.data?.details)||j?.data?.summary?.totals))payloads.push(j.data);
      if(Array.isArray(j)){
        for(const r of j){
          if(r?.summary&&(Array.isArray(r?.details)||r?.summary?.totals))payloads.push(r);
          if(r?.data?.summary&&(Array.isArray(r?.data?.details)||r?.data?.summary?.totals))payloads.push(r.data);
        }
      }
    }
  }
  const citems=safeItems(CREANCE_NODE);
  for(const it of citems){
    let j=it?.json;
    if(!j)continue;
    if(typeof j==='string'){try{j=JSON.parse(j)}catch{continue}}
    if(j?.summary&&(Array.isArray(j?.details)||j?.summary?.totals))payloads.push(j);
    if(j?.data?.summary&&(Array.isArray(j?.data?.details)||j?.data?.summary?.totals))payloads.push(j.data);
    if(Array.isArray(j)){
      for(const r of j){
        if(r?.summary&&(Array.isArray(r?.details)||r?.summary?.totals))payloads.push(r);
        if(r?.data?.summary&&(Array.isArray(r?.data?.details)||r?.data?.summary?.totals))payloads.push(r.data);
      }
    }
  }
  return payloads;
}

function extractCreanceSummaryData(){
  const payloads=collectCreancePayloads();
  let totals=null;
  let balances=[];
  for(const p of payloads){
    const s=p?.summary||p?.data?.summary||null;
    if(!s)continue;
    if(!totals&&s.totals){
      totals={
        current_balance:toNumber(s.totals.current_balance),
        previous_balance:toNumber(s.totals.previous_balance),
        total_difference:toNumber(s.totals.total_difference),
      };
    }
    if(balances.length===0&&Array.isArray(s.portfolios)){
      balances=s.portfolios.map(x=>({
        portfolio_name:x.portfolio_name||x.portfolio||x.portefeuille||'Portefeuille',
        current_balance:toNumber(x.current_balance),
      }));
    }
    if(totals&&balances.length)break;
  }
  return{totals,balances};
}

/* ------------------------------------------------------------------ 
 *            Analytics (marges & CA mensuels)                        
 * ------------------------------------------------------------------ */
function findFirstAnalyticsRoot(){
  const candidates = [];
  if(typeof items !== 'undefined' && items && Array.isArray(items)){
    for(const it of items){
      if(it?.json) candidates.push(it.json);
    }
  }
  for(const it of safeItems(ANALYTICS_NODE)){
    if(it?.json) candidates.push(it.json);
  }
  for(const j0 of candidates){
    let j=j0;
    if(typeof j==='string'){
      try{ j=JSON.parse(j);}catch{}
    }
    const root = j?.analytics || j?.data?.analytics || j;
    const hasTotals = root?.totauxGeneraux || root?.totaux || root?.totaux_generaux;
    if(hasTotals || root?.proxyMarges) return root;
  }
  return null;
}

function extractAnalytics(){
  const root = findFirstAnalyticsRoot();
  if(!root) return { totals:null, pvMap:new Map() };

  const tg = root?.totauxGeneraux || root?.totaux || root?.totaux_generaux || {};
  const totals = {
    caSans : toNumber(tg.totalChiffreAffairesSansStockSoir ?? tg.caSans ?? tg.total_ca_sans_stock_soir),
    margeSans: toNumber(tg.totalMargeSansStockSoir ?? tg.margeSans ?? tg.total_marge_sans_stock_soir),
    caIncl : toNumber(tg.totalChiffreAffaires ?? tg.ca ?? tg.total_ca),
    margeIncl: toNumber(tg.totalMarge ?? tg.marge ?? tg.total_marge),
  };

  const pvRaw = root?.proxyMarges || root?.pv || root?.pointsDeVente || {};
  const pvMap = new Map();
  if(pvRaw && typeof pvRaw==='object'){
    for(const [pvName, obj] of Object.entries(pvRaw)){
      const t = obj?.totaux || obj || {};
      pvMap.set(String(pvName), {
        caSans : toNumber(t.totalChiffreAffairesSansStockSoir ?? t.caSans),
        margeSans: toNumber(t.totalMargeSansStockSoir ?? t.margeSans),
        caIncl : toNumber(t.totalChiffreAffaires ?? t.ca),
        margeIncl: toNumber(t.totalMarge ?? t.marge),
      });
    }
  }
  return { totals, pvMap };
}

function getPvAnalytics(pvMap, name){
  if(!pvMap||!name)return null;
  // match exact
  for(const [k,v] of pvMap.entries()){
    if(pvKey(k)===pvKey(name)) return v;
  }
  return null;
}

/* ------------------------------------------------------------------ 
 *               Lecture « Get Rec from matix »                       
 * ------------------------------------------------------------------ */
function transformTargetToResume(targetArr){
  if(!Array.isArray(targetArr)||targetArr.length===0)return null;
  const t=targetArr[targetArr.length-1]||{};
  const points=Array.isArray(t.pointsDeVente)?t.pointsDeVente:[];
  const out=[];
  for(const pv of points){
    const name=pv.PointDeVente??pv.pointVente??pv.pdv??'Point de Vente';
    const details=Array.isArray(pv.details)?pv.details:[];
    let vs=0;
    let vt=0;
    for(const d of details){
      const prod=d.Produit??d.produit??d.product;
      if(!keepProduct(prod))continue;
      const stockMatin=toNumber(d.StockMatin??d.stock_matin??d.stockMatin);
      const stockSoir =toNumber(d.StockSoir ??d.stock_soir ??d.stockSoir);
      const transf =toNumber(d.Transferts??d.transferts??d.transfertsNombre);
      const vTheo =toNumber(d.VentesTheoriques??d.ventesTheoriques);
      const vSaisies =stockMatin+transf-stockSoir;
      vs+=vSaisies;
      vt+=vTheo;
    }
    if(vs===0&&vt===0)continue;
    const ecart=vt-vs;
    const ecartPct=(Math.abs(vt)>0)?(ecart/Math.abs(vt))*100:0;
    out.push({pointVente:name,ventesSaisies:vs,ventesTheoriques:vt,cashPayments:0,ecart,ecartPct,ecartCash:0,ecartCashPct:0});
  }
  return{date:normalizeDateStr(t.date??t.Date??t.jour),resume:out};
}

function collectRecData(){
  // 1) essayer dans "items"
  if(typeof items !== 'undefined' && items && Array.isArray(items)){
    for(const it of items){
      let j=it?.json;
      if(!j)continue;
      if(typeof j==='string'){try{j=JSON.parse(j)}catch{}}
      if(j?.resume&&Array.isArray(j.resume))return j;
      if(j?.data?.resume&&Array.isArray(j.data.resume))return j.data;
      if(Array.isArray(j?.target)){const t=transformTargetToResume(j.target); if(t)return t;}
      if(Array.isArray(j?.data?.target)){const t=transformTargetToResume(j.data.target); if(t)return t;}
      if(Array.isArray(j)){
        for(const r of j){
          if(r?.resume&&Array.isArray(r.resume))return r;
          if(r?.data?.resume&&Array.isArray(r.data.resume))return r.data;
          if(Array.isArray(r?.target)){const t=transformTargetToResume(r.target); if(t)return t;}
          if(Array.isArray(r?.data?.target)){const t=transformTargetToResume(r.data.target); if(t)return t;}
        }
      }
    }
  }
  // 2) essayer dans les nodes REC_NODES
  for(const name of REC_NODES){
    const arr=safeItems(name);
    for(const it of arr){
      let j=it?.json;
      if(!j)continue;
      if(typeof j==='string'){try{j=JSON.parse(j)}catch{}}
      if(j?.data?.resume&&Array.isArray(j.data.resume))return j.data;
      if(j?.resume&&Array.isArray(j.resume))return j;
      if(Array.isArray(j?.target)){const t=transformTargetToResume(j.target); if(t)return t;}
      if(Array.isArray(j?.data?.target)){const t=transformTargetToResume(j.data.target); if(t)return t;}
      if(Array.isArray(j)){
        for(const r of j){
          if(r?.data?.resume&&Array.isArray(r.data.resume))return r.data;
          if(r?.resume&&Array.isArray(r.resume))return r;
          if(Array.isArray(r?.target)){const t=transformTargetToResume(r.target); if(t)return t;}
          if(Array.isArray(r?.data?.target)){const t=transformTargetToResume(r.data.target); if(t)return t;}
        }
      }
    }
  }
  return null;
}

function pickSelectedDateNorm(data,recData){
  const d1=normalizeDateStr(data?.date);
  if(d1)return d1;
  if(typeof items !== 'undefined' && items && Array.isArray(items) && items.length > 0){
    const d2=normalizeDateStr(items[0]?.json?.summary?.date_selected);
    if(d2)return d2;
  }
  const payloads=collectCreancePayloads();
  for(const p of payloads){const d=normalizeDateStr(p?.summary?.date_selected); if(d)return d;}
  const d3=normalizeDateStr(recData?.date);
  if(d3)return d3;
  return '';
}

/* ------------------------------------------------------------------ 
 *            Opérations portefeuille (créances / bank)               
 * ------------------------------------------------------------------ */
function buildOpsByPortfolioForDate(selectedDateNorm){
  const map=new Map();
  const seen=new Set();
  let diag={payloads:0,portfolios:0,opsScanned:0,opsKept:0,dupBlocked:0};

  function pushOp(portfolioName,op){
    const dateStr=op.date_operation||op.operation_date||op.date||op.timestamp;
    const dNorm=normalizeDateStr(dateStr);
    diag.opsScanned+=1;
    if(!dNorm||dNorm!==selectedDateNorm)return;
    const amt=toNumber(op.montant??op.amount);
    const time=extractTimeStr(op.timestamp||op.date||'');
    const typ=op.type||'Opération';
    const ref=op.client||op.reference||'s/o';
    const keyPortfolio=String(portfolioName||'Portefeuille').trim();
    const uniq=`${keyPortfolio}|${dNorm}|${typ}|${ref}|${amt}|${time}`;
    if(seen.has(uniq)){diag.dupBlocked+=1;return;}
    seen.add(uniq);
    if(!map.has(keyPortfolio))map.set(keyPortfolio,{total:0,ops:[]});
    const entry=map.get(keyPortfolio);
    entry.total+=amt;
    entry.ops.push({type:typ,ref,amount:amt,time});
    diag.opsKept+=1;
  }

  const payloads=collectCreancePayloads();
  diag.payloads=payloads.length;
  for(const p of payloads){
    const details=Array.isArray(p?.details)?p.details:(Array.isArray(p?.data?.details)?p.data.details:[]);
    diag.portfolios+=details.length;
    for(const pf of details){
      const name=pf?.portfolio_name||pf?.portfolio||pf?.portefeuille;
      const ops=Array.isArray(pf?.operations)?pf.operations:[];
      if(!name||ops.length===0)continue;
      for(const op of ops)pushOp(name,op);
    }
  }

  const flatCandidates=['OperationsPortefeuille','Operations','Ops','Code2'];
  const flatItems=flatCandidates.flatMap((n)=>safeItems(n));
  for(const it of flatItems){
    let j=it?.json;
    if(!j)continue;
    if(typeof j==='string'){try{j=JSON.parse(j)}catch{continue}}
    const rows=Array.isArray(j)?j:(Array.isArray(j.data)?j.data:[j]);
    for(const row of rows){
      const pf=row.portfolio_name??row.portefeuille??row.portfolio??row.Portefeuille;
      pushOp(pf,row);
    }
  }

  for(const [,entry] of map){
    entry.ops.sort((a,b)=>{if(a.time&&b.time&&a.time!==b.time)return b.time.localeCompare(a.time);return Math.abs(b.amount)-Math.abs(a.amount);});
  }
  return {map,diag};
}

/* ------------------------------------------------------------------ 
 *         NOUVEAU : importantInfo (par point de vente)               
 * ------------------------------------------------------------------ */
function buildImportantInfo(resumes, creanceMap, virementMap, mlcData, breakTolerance = BREAK_TOLERANCE){
  const out = {};

  for(const res of (Array.isArray(resumes) ? resumes : [])){
    const pv = res?.pointVente || 'Point de Vente';

    // Vente CD Exécutée (affiché seulement, n'intervient plus dans les calculs)
    const venteCdExecutee = toNumber(res?.ventesSaisiesRecuesParCentreDecoupe);

    // ✅ res.ecart et res.ecartPct sont déjà ajustés côté API (intègrent venteCD)
    const ecartValue = toNumber(res?.ecart);
    const ecartPct = toNumber(res?.ecartPct);

    // Delta créance
    const creanceInfo = creanceMap?.get(pvKey(pv)) || null;
    const deltaCreance = toNumber(creanceInfo?.diff);

    // Virement
    const virement = toNumber(getVirementForPv(virementMap, pv));

    // ✅ res.ecartCash est déjà ajusté côté API (intègre venteCD)
    const isAbattage = pvKey(pv) === pvKey('abattage');
    let ecartCashValue = toNumber(res?.ecartCash);

    // Spécifique Abattage : écartCash = cashPayments - ventesSaisies (comme dans le HTML)
    if(isAbattage){
      const cashPayments = toNumber(res?.cashPayments);
      const ventesSaisies = toNumber(res?.ventesSaisies);
      ecartCashValue = cashPayments - ventesSaisies;
    }

    // ✅ Break = Écart Cash + Delta Créance + Virement
    const breakSum = ecartCashValue + deltaCreance + virement;
    const breakOK = Math.abs(breakSum) <= toNumber(breakTolerance);

    // Retour clients (MLC)
    let retourClients = null;
    if(mlcData){
      const sentiment = getMlcSentimentForPv(mlcData, pv);
      if(sentiment && sentiment.sentiment_description){
        retourClients = {
          description: sentiment.sentiment_description,
          date_analyse: sentiment.date_analyse ? normalizeDateStr(sentiment.date_analyse) : '',
          nombre_commentaires: toNumber(sentiment.nombre_commentaires || 0),
          notes_detaillees: sentiment.notes_detaillees || null
        };
      }
    }

    out[pv] = {
      ecartVente: {
        valeur: ecartValue,
        pct: ecartPct
      },
      breaks: {
        statut: breakOK ? 'No Break' : 'Break',
        valeur: breakSum
      },
      venteCdExecutee,
      retourClients // null si absent
    };
  }

  return out;
}

