`;

  /* ---------------------
     Carte « Marge totale du mois »
     --------------------- */
  if(analyticsTotals && (analyticsTotals.margeSans>0 || analyticsTotals.margeIncl>0)){
    const pctSans = pct(analyticsTotals.margeSans, analyticsTotals.caSans);
