      const delta = (pack.deltaKg>=0?'+':'') + Number(pack.deltaKg.toFixed(1));
      return `${lbl} : Δ = ${delta} kg, ${spanPercent((pack.pct||0)*100)} <br/><span style="font-size:12px;color:#6B7280">(${formatNumber(Number(pack.soldKg.toFixed(1)))} / ${formatNumber(Number(pack.theoKg.toFixed(1)))} kg)</span>`;
