    let commentText = getResumeComment(res);
    let commentCell;
    if(pvKey(pointVente)===pvKey('abattage') && shouldHideCommentForAbattage(commentText)){
      commentText='';
      commentCell=`<td style="${tdPV}"></td>`;
    } else {
      commentCell=`<td style="${tdPV}">${commentText?esc(commentText):'—'}</td>`;
    }

    if(pvKey(pointVente)===pvKey('abattage')){
      const abEcartCash = toNumber(cashPayments) - toNumber(ventesSaisies);
      const abEcartCashPct = (Math.abs(toNumber(cashPayments))>0)?(abEcartCash/Math.abs(toNumber(cashPayments)))*100:0;

      // ✅ Break = écartCash + deltaCréance + virement (ecartCash déjà ajusté côté API)
      const breakSum = abEcartCash + toNumber(creanceValue) + toNumber(virementValue);
