        <td style="${tdPV}">—</td>
        <td style="${tdPV}">—</td>
        ${commentCell}
      </tr>`;
    } else {
      // ✅ ecart et ecartPct sont déjà ajustés côté API
      const pctAlert = toNumber(ecartPct) > ALERT_ECART_PCT;
      const cashAlert = toNumber(ecartCash) > ALERT_ECART_CASH;

      // ✅ Break = écartCash + deltaCréance + virement (ecartCash déjà ajusté côté API)
      const breakSum = toNumber(ecartCash) + toNumber(creanceValue) + toNumber(virementValue);
      const breakOK = Math.abs(breakSum) <= BREAK_TOLERANCE;
