        <td style="${tdPV}">${breakCell}</td>
        <td style="${tdPV}">${spanAmount(ecartCash)}<div style="font-size:12px;color:${cashAlert?'#C62828':'#64748B'};">(${pctStr(ecartCashPct)})</div></td>
        <td style="${tdPV}">${spanAmount(creanceValue)} <div style="font-size:12px;color:#64748B;">(${esc(creanceLabelDate)})</div></td>
