  html += `</tbody></table>`;

  /* ---------- Légende des formules ---------- */
  html += `<div style="margin:6px 0 14px 0; padding:8px 10px; background:#F8FAFC; border:1px solid #E5E7EB; border-radius:8px; color:#374151; font-size:12px;">
