    <div style="margin-top:2px;">
      • <strong>Break</strong> :
      <span style="font-family:ui-monospace, SFMono-Regular, Menlo, Monaco, Consolas, 'Liberation Mono', 'Courier New', monospace;">
        Break = Écart Cash + Delta Créance + Virement
      </span>
    </div>
  </div>`;

  // Alertes
  if(alerts.length){
    html += `<div style="${sectionTitle}">Alertes</div><ul style="margin:6px 0 10px 18px;padding:0;color:#B71C1C;">${alerts.map(a=>`<li>${a}</li>`).join('')}</ul>`;
  }

  // Opérations par portefeuille
  html += `<div style="${sectionTitle}">Opérations par portefeuille – Date sélectionnée : ${esc(selected)}</div>`;

  if(!opsByPortfolioMap || opsByPortfolioMap.size===0){
    html += `<div style="padding:10px;border:1px dashed #CBD5E1;border-radius:8px;background:#F8FAFC;color:#475569;">Aucune opération trouvée pour la date sélectionnée.</div>`;
  }else{
    const portfolios = Array.from(opsByPortfolioMap.keys()).sort((a,b)=>String(a).localeCompare(String(b),'fr'));
    for(const pf of portfolios){
      const entry=opsByPortfolioMap.get(pf);
      html += `<div style="margin:12px 0 4px 0;font-weight:700;color:#111827;">Portefeuille : ${esc(pf)}</div>
