        <tbody>${entry.ops.map(op=>`<tr><td style="${tdBase}">${esc(op.time||'')}</td><td style="${tdBase}">${esc(op.type)}</td><td style="${tdBase}">${esc(op.ref)}</td><td style="${tdBase};text-align:right;">${spanAmount(op.amount)}</td></tr>`).join('')}</tbody>
      </table>`;
    }
  }

  if(DIAG){
    html += `<div style="${sectionTitle}">[DEBUG]</div><pre style="white-space:pre-wrap;font-size:12px;color:#6B7280;background:#F3F4F6;border:1px solid #E5E7EB;border-radius:8px;padding:8px;">${esc(JSON.stringify(opsPack?.diag||{},null,2))}</pre>`;
  }

  html += `<div style="margin-top:14px;font-size:12px;color:#64748B;">Généré automatiquement – DSI MATA / MLC • ${new Date().toISOString().slice(0,16).replace('T',' ')} UTC</div></div></div>`;

  return html;
}

