// n8n Function node
//
// Agrégation des ventes théoriques des produits cibles par date & point de vente,
// en lisant UNIQUEMENT les données du nœud "Get Rec from matix2".
//
// Règles spéciales :
// - Exclure Abattage.
// - Pour Linguere & Dahra : ne considérer que Poulet (autres produits forcés à 0).
// - Ordre PV : O.Foire, Mbao, Keur Massar, Sacre Coeur, puis reste alphabétique.
//
// Auteur : adapté pour Saliou / MATA
// Maj : 18-07-2025
//----------------------------------------------------------------

//////////////////// CONFIG ////////////////////
const SOURCE_NODE = "Get Rec from matix2";
const TARGET_PRODUCTS = ["Boeuf", "Veau", "Agneau", "Poulet", "Yell", "Foie"];
const EXCLUDED_POINTS = ["Abattage"];
const PV_ONLY_POULET = ["Linguere", "Dahra"];
const ORDER_FIRST = ["O.Foire", "Mbao", "Keur Massar", "Sacre Coeur"];
///////////////////////////////////////////////


// ---------- Utilitaires ----------
function norm(str) {
  if (typeof str !== 'string') return '';
  return str
    .normalize('NFD').replace(/[\u0300-\u036f]/g, '')
    .toLowerCase()
    .replace(/\s+/g, ' ')
    .trim();
}

const EXCLUDED_NORM = new Set(EXCLUDED_POINTS.map(norm));
function isExcludedPointVente(pv) {
  return EXCLUDED_NORM.has(norm(pv));
}

const PV_ONLY_POULET_NORM = new Set(PV_ONLY_POULET.map(norm));
function allowedProductsForPv(pv) {
  return PV_ONLY_POULET_NORM.has(norm(pv)) ? ["Poulet"] : TARGET_PRODUCTS;
}

// dictionnaire norm -> canon
const canonicalMap = {};
for (const p of TARGET_PRODUCTS) canonicalMap[norm(p)] = p;

// Test clé date DD-MM-YYYY
const DATE_RE = /^(\d{2})-(\d{2})-(\d{4})$/;

function parseDateKey(dk) {
  const m = DATE_RE.exec(dk);
  if (!m) return null;
  const [ , dd, mm, yyyy ] = m;
  return new Date(Number(yyyy), Number(mm) - 1, Number(dd));
}

function sortDateKeys(dateKeys) {
  return [...dateKeys].sort((a, b) => {
    const da = parseDateKey(a);
    const db = parseDateKey(b);
    if (!da && !db) return a.localeCompare(b);
    if (!da) return 1;
    if (!db) return -1;
    return da - db;
  });
}

function toNum(v) {
  const n = Number(v);
  return Number.isFinite(n) ? n : 0;
}


// ---------- Extraction produits cibles à partir d'un objet produit brut ----------
/*
 * produitsObj structure attendue :
 * {
 *   "Boeuf": { ventesTheoriques: 123, ... },
 *   "Tablette": {...}, ...
 * }
 * Nous ne retenons que TARGET_PRODUCTS, en respectant la règle PV_ONLY_POULET.
 */
function extractProductsForPv(produitsObj, pv) {
  const allowed = allowedProductsForPv(pv);
  const out = {};
  // init 0 pour chaque produit autorisé
  for (const p of allowed) out[p] = 0;

  if (!produitsObj || typeof produitsObj !== 'object') return out;

  for (const [lib, pdata] of Object.entries(produitsObj)) {
    const canon = canonicalMap[norm(lib)];
    if (!canon) continue;            // produit hors cible
    if (!allowed.includes(canon)) continue; // filtré par règle PV_ONLY_POULET
    const vt = Number(pdata?.ventesTheoriques);
    if (Number.isFinite(vt)) out[canon] += vt;
  }
  return out;
}


// ---------- Fusion/agrégation principale ----------
/*
 * Parcourt tous les items du nœud source, agrège vers :
 * grouped = { date: { pointVente: { prod: totalVT } } }
 */
function collectFromSource() {
  const srcItems = $items(SOURCE_NODE, 0, 0) || [];
  const grouped = {};

  for (const item of srcItems) {
    const data = item.json?.data;
    if (!data) continue;

    const date = data.date ?? 'inconnue';

    // le détail exploitable est sous data.details
    const details = data.details ?? {};
    if (!grouped[date]) grouped[date] = {};

    for (const [pointVente, produitsObj] of Object.entries(details)) {
      if (isExcludedPointVente(pointVente)) continue;

      // obtenir (prod->val) pour ce PV
      const prodVals = extractProductsForPv(produitsObj, pointVente);

      // accumuler
      if (!grouped[date][pointVente]) grouped[date][pointVente] = {};
      for (const [prod, val] of Object.entries(prodVals)) {
        grouped[date][pointVente][prod] =
          (grouped[date][pointVente][prod] ?? 0) + toNum(val);
      }
    }
  }

  return grouped;
}


// ---------- Construire l'ordre des points de vente ----------
function buildOrderedPvList(grouped) {
  const set = new Set();
  for (const d of Object.keys(grouped)) {
    Object.keys(grouped[d] || {}).forEach(pv => set.add(pv));
  }
  const all = [...set];
  // tri custom
  return all.sort((a, b) => {
    const na = norm(a);
    const nb = norm(b);
    const ia = ORDER_FIRST.findIndex(x => norm(x) === na);
    const ib = ORDER_FIRST.findIndex(x => norm(x) === nb);
    if (ia === -1 && ib === -1) return a.localeCompare(b);
    if (ia === -1) return 1;
    if (ib === -1) return -1;
    return ia - ib;
  });
}


// ---------- Programme principal ----------
const grouped = collectFromSource();
const dates = sortDateKeys(Object.keys(grouped));
const orderPointVente = buildOrderedPvList(grouped);

// Option : garantir que tous les PV possèdent toutes les clés produits autorisées
// (pour faciliter tableaux en aval)
for (const date of dates) {
  for (const pv of Object.keys(grouped[date])) {
    const allowed = allowedProductsForPv(pv);
    for (const prod of allowed) {
      if (grouped[date][pv][prod] == null) grouped[date][pv][prod] = 0;
    }
  }
}

// ----- Sortie -----
// Un seul item structuré, avec méta-infos d'ordre
return [{
  json: {
    dates,
    orderPointVente,
    data: grouped,
    config: {
      targetProducts: TARGET_PRODUCTS,
      pvOnlyPoulet: PV_ONLY_POULET,
      excludedPoints: EXCLUDED_POINTS,
      orderFirst: ORDER_FIRST,
    }
  }
}];

// n8n Function node
//
// Transforme un input agrégé (dates + orderPointVente + data)
// en un objet {date:{pointVente:{Boeuf..}}} normalisé,
// avec les 6 produits cibles forcés (0 si absent),
// et en EXCLUANT "Abattage" (même si présent dans data).
//
// Sortie: [ { json: { "DD-MM-YYYY": { pv: {prod:val} ... }, ... } } ]
//
// Maj: 18-07-2025 (excl. Abattage)
//----------------------------------------------------------------

//////////////////// CONFIG ////////////////////
const TARGET_PRODUCTS = ["Boeuf", "Veau", "Agneau", "Poulet", "Yell", "Foie"];
///////////////////////////////////////////////

// ------------------------------------------------------------------
// 1. Récup input unique
// ------------------------------------------------------------------
const input = items[0]?.json;
if (!input) {
  return [{ json: { error: "Input vide ou invalide." } }];
}

const dates = Array.isArray(input.dates) ? input.dates : [];
// On respecte l'ordre fourni; Abattage n'y figure pas => exclu.
const orderPointVente = Array.isArray(input.orderPointVente) ? input.orderPointVente : [];
const data = input.data || {};  // {date:{pv:{prod:val}}}

// ------------------------------------------------------------------
// 2. Normaliser map produits -> 6 produits cibles
// ------------------------------------------------------------------
function ensureAllProducts(prodMap) {
  const out = {};
  for (const p of TARGET_PRODUCTS) {
    const v = prodMap?.[p];
    const n = Number(v);
    out[p] = Number.isFinite(n) ? n : 0;
  }
  return out;
}

// ------------------------------------------------------------------
// 3. Construire objet final sans Abattage
// ------------------------------------------------------------------
const finalObj = {};

for (const d of dates) {
  const pvMapIn = data[d] || {};
  const pvMapOut = {};

  for (const pv of orderPointVente) {
    const rawProdMap = pvMapIn[pv];
    pvMapOut[pv] = ensureAllProducts(rawProdMap);
  }

  finalObj[d] = pvMapOut;
}

// ------------------------------------------------------------------
// 4. Sortie
// ------------------------------------------------------------------
return [{ json: finalObj }];

/* ===============================================================
   n8n Function node — Email "Evolution VT" (HTML + Text)
   Entrée (items[0].json) : agrégat VT multi-dates par PV
     {
       "01-09-2025": { "O.Foire": {...}, "Mbao": {...}, ... },
       "02-09-2025": { ... },
       "03-09-2025": { ... }
     }
   - Produits VT: Boeuf, Veau, Agneau, Poulet, Yell, Foie
   - Produits Stocks du soir: + Tablette
   - PV exclus (Evolution VT): Abattage
   - PV exclus (Stocks du soir): Abattage, Chambre froide
   - Règle spéciale: à Linguere & Dahra, on n’évalue que "Poulet" pour la stagnation
   Sortie: [{ json: { subject, html, text, dates, ... } }]
   =============================================================== */

/* =====================  CONFIG  ===================== */
const TARGET_PRODUCTS = ["Boeuf","Veau","Agneau","Poulet","Yell","Foie"];
const ORDER_PV = ["O.Foire","Mbao","Keur Massar","Sacre Coeur","Dahra","Linguere"];
const VARIATION_THRESHOLD = 0.05; // 5 %
const EXCLUDED_PV = new Set(["Abattage"]);                       // Evolution VT
const EXCLUDED_STOCKS_PV = new Set(["Abattage","Chambre froide"]); // Stocks du soir
const LIMIT_TO_LAST_N_DATES = 3;
const SHOW_PCT_CHANGE = true;

// --- Nom EXACT du nœud qui fournit { data:{ details:{...} } } ---
const GET_REC_NODE = 'Get Rec from matix2';

// Produits affichés dans les tableaux "Évolution VT" par PV (masquer Agneau, Yell, Foie en Chambre froide)
const PV_EVOLUTION_PRODUCTS_OVERRIDE = {
  "Chambre froide": ["Boeuf", "Veau", "Poulet"],
};
// Helper : liste de produits à afficher pour un PV donné
function getProductsForPV(pv){
  return PV_EVOLUTION_PRODUCTS_OVERRIDE[pv] || TARGET_PRODUCTS;
}

/* =====================  Styles  ===================== */
const C = {
  bg:"#F8FAFC", card:"#FFFFFF", ink:"#0F172A", sub:"#475569",
  border:"#E5E7EB", borderLight:"#F1F5F9",
  thBg:"#F8FAFC", thTxt:"#111827", tdTxt:"#111827",
  chipInfoBg:"#EEF2FF", chipInfoTxt:"#1E40AF", chipInfoBr:"#C7D2FE",
  chipOkBg:"#E8F5E9", chipOkTxt:"#1B5E20", chipOkBr:"#A5D6A7",
  chipWarnBg:"#FFF8E1", chipWarnTxt:"#8D6E00", chipWarnBr:"#FFE082",
  chipErrBg:"#FFEBEE", chipErrTxt:"#B71C1C", chipErrBr:"#EF9A9A",
  stagnBg:"#FFF4F4", stagnTxt:"#B71C1C",
  zeroBg:"#FFFBEA", zeroTxt:"#8D6E00",
};

/* =====================  Utils  ===================== */
const DATE_RE = /^(\d{2})-(\d{2})-(\d{4})$/;
const esc = s => String(s ?? "").replace(/[&<>"']/g, c => (
  { "&":"&amp;", "<":"&lt;", ">":"&gt;", '"':"&quot;", "'":"&#39;" }[c]
));
function parseDateKey(dk){ const m = DATE_RE.exec(dk); if (!m) return null; const [,dd,mm,yyyy]=m; return new Date(+yyyy,+mm-1,+dd); }
function sortDateKeys(keys){
  return [...keys].sort((a,b)=>{
    const da=parseDateKey(a), db=parseDateKey(b);
    if (!da && !db) return a.localeCompare(b);
    if (!da) return 1; if (!db) return -1; return da-db;
  });
}
const toNum = v => Number.isFinite(Number(v)) ? Number(v) : 0;
const pctFmt = (v,d=1)=> (v*100).toFixed(d)+"%";
function numFmtFlexible(v){
  const n = Number(v); if (!Number.isFinite(n)) return "0";
  const isInt = Math.abs(n - Math.round(n)) < 1e-9;
  return n.toLocaleString('fr-FR',{ minimumFractionDigits: isInt?0:2, maximumFractionDigits: isInt?0:2 });
}
function chip(text,kind='info'){
  const map = {
    info:{bg:C.chipInfoBg,br:C.chipInfoBr,txt:C.chipInfoTxt},
    ok:{bg:C.chipOkBg,br:C.chipOkBr,txt:C.chipOkTxt},
    warn:{bg:C.chipWarnBg,br:C.chipWarnBr,txt:C.chipWarnTxt},
    danger:{bg:C.chipErrBg,br:C.chipErrBr,txt:C.chipErrTxt},
  }[kind] || {bg:"#EEE",br:"#DDD",txt:"#333"};
  return `<span style="display:inline-block;padding:2px 8px;border:1px solid ${map.br};border-radius:999px;background:${map.bg};color:${map.txt};font-size:12px;line-height:18px;">${esc(text)}</span>`;
}
function spanAmount(n){
  const v = toNum(n);
  const color = v < 0 ? "#C0392B" : (v > 0 ? "#1E8449" : C.tdTxt);
  const fw = v !== 0 ? "600" : "500";
  return `<span style="color:${color};font-weight:${fw}">${numFmtFlexible(v)}</span>`;
}
function computeMetrics(vals, checkStagnation=true){
  const first = vals[0] ?? 0, last = vals.at(-1) ?? 0;
  let min=Infinity,max=-Infinity; for (const v of vals){ if (v<min) min=v; if (v>max) max=v; }
  if (min===Infinity) min=0; if (max===-Infinity) max=0;
  const range = max-min; const pctRange = max!==0 ? Math.abs(range)/Math.abs(max) : 0;
  let pctChange; if (first===0 && last===0) pctChange=0; else if (first===0) pctChange = max!==0 ? (last-first)/Math.abs(max) : 0;
  else pctChange = (last-first)/Math.abs(first);
  const stagnant = checkStagnation ? (pctRange < VARIATION_THRESHOLD) : false;
  return {first,last,min,max,pctRange,pctChange,stagnant};
}

/* =====================  1) Lire input principal (agrégat VT)  ===================== */
const rawObj = items[0]?.json;
if (!rawObj || typeof rawObj !== 'object') {
  return [{ json: { error:"Input vide ou invalide pour Evolution VT (aggregated)." } }];
}

/* =====================  2) Dates cibles  ===================== */
const allDateKeys = sortDateKeys(Object.keys(rawObj));
const dates = LIMIT_TO_LAST_N_DATES ? allDateKeys.slice(-LIMIT_TO_LAST_N_DATES) : allDateKeys;
const periodStr = dates.length ? `${dates[0]} → ${dates.at(-1)}` : "—";

/* =====================  3) PV ordonnés  ===================== */
const pvSet = new Set(ORDER_PV);
for (const d of dates){
  const pvMap = rawObj[d] || {};
  Object.keys(pvMap).forEach(pv => { if (!EXCLUDED_PV.has(pv)) pvSet.add(pv); });
}
const pvOrdered = ORDER_PV.concat([...pvSet].filter(pv => !ORDER_PV.includes(pv)));

/* =====================  4) Séries & métriques par PV (Evolution VT)  ===================== */
const pvData = {};
for (const pv of pvOrdered){
  if (EXCLUDED_PV.has(pv)) continue;
  const series = [];
  for (const d of dates){
    const pvMap = rawObj[d]?.[pv] || {};
    const row = { date:d };
    for (const prod of TARGET_PRODUCTS) row[prod] = toNum(pvMap[prod]);
    series.push(row);
  }
  const metrics = {};
  for (const prod of TARGET_PRODUCTS){
    let check = true;
    if ((pv==="Linguere" || pv==="Dahra") && prod!=="Poulet") check = false;
    metrics[prod] = computeMetrics(series.map(r=>r[prod]), check);
  }
  pvData[pv] = {pointVente:pv, series, metrics};
}

/* =====================  5) Lecture "Get Rec" (stocks du soir)  ===================== */
function _unwrapGetRecPayload(x){
  if (!x) return null;
  if (Array.isArray(x)){
    const a = x.find(e => e?.data?.details && typeof e.data.details === 'object'); if (a) return a.data;
    const b = x.find(e => e?.details && typeof e.details === 'object'); if (b) return b;
    return null;
  }
  if (x?.data?.details && typeof x.data.details === 'object') return x.data;
  if (x?.details && typeof x.details === 'object') return x;
  return null;
}
function _detectGetRecData(){
