  const card = `background:${C.card};border:1px solid ${C.border};border-radius:12px;box-shadow:0 1px 2px rgba(0,0,0,.04);padding:12px;`;

  const parts = [];
  parts.push(`<div style="${container}"><div style="${wrap}">`);

  // Carte 1 — Stocks du soir
  const hasStocks = __getRecData?.details && typeof __getRecData.details === 'object';
  parts.push(`<div style="${card}">` + (
    hasStocks
      ? buildStocksSoirFromGetRecHTML(__getRecData.details)
      : `<div style="font-size:12px;color:${C.sub};">${chip('Source Get Rec introuvable ou vide','warn')} <span style="margin-left:6px">Vérifiez le nœud <em>${esc(GET_REC_NODE)}</em> et la présence de <code>data.details</code>.</span></div>`
  ) + `</div>`);

  // Carte 2 — Evolution VT + résumé fusionné
  parts.push(`
    <div style="${card}">
      <div style="display:flex;align-items:center;gap:8px;margin-bottom:4px;">
        <div style="font-size:18px;font-weight:800;color:${C.ink};">Évolution des Ventes Théoriques</div>
        ${chip("VT","info")}
      </div>
      <div style="font-size:13px;color:${C.sub};margin-bottom:10px;">
        Période : <strong>${esc(periodStr)}</strong> &nbsp;•&nbsp; Seuil stagnation : <strong>&lt; ${pctFmt(VARIATION_THRESHOLD)}</strong>
      </div>
      ${buildSummariesHTML()}
  `);
  for (const pv of pvOrdered){ 
    if (!EXCLUDED_PV.has(pv)) { 
      const rec = pvData[pv]; 
      if (rec) parts.push(buildTableForPV(rec)); 
    } 
  }

  // Légende
  parts.push(`
      <div style="margin-top:10px;font-size:12px;color:${C.sub};">
        <div style="margin:6px 0 2px 0;font-weight:700;color:${C.ink};">Légende</div>
        <div>${chip("⚠️ Stagnant","warn")} : Amplitude relative &lt; ${pctFmt(VARIATION_THRESHOLD)} sur la période (à Linguere &amp; Dahra : seul <strong>Poulet</strong> évalué).</div>
        <div>Dans « Stocks du soir », les valeurs <strong>0</strong> sont surlignées et les PV <em>Abattage</em> & <em>Chambre froide</em> sont exclus.</div>
      </div>
    </div>
  `);

  // Pied
  parts.push(`
    <div style="text-align:center;color:${C.sub};font-size:12px;margin-top:10px;">
      Généré automatiquement — DSI MATA • ${new Date().toISOString().slice(0,16).replace('T',' ')} UTC
    </div>
  `);

  parts.push(`</div></div>`);
  global.htmlReport = parts.join("\n");
})();

/* ===================== 10) Texte ===================== */
const textParts = [];
textParts.push(`Evolution des Ventes Théoriques`);
textParts.push(`Période: ${periodStr} | Seuil stagnation: < ${pctFmt(VARIATION_THRESHOLD)}`);

const stocksText = (__getRecData?.details) ? buildStocksSoirFromGetRecTEXT(__getRecData.details)
  : `Source Get Rec introuvable ou vide (nœud: ${GET_REC_NODE}).`;
textParts.push(stocksText, "", buildSummariesText(), "", buildTextDetails());

/* ===================== 11) Sortie ===================== */
return [{
  json: {
    subject: `📈 Evolution VT — ${periodStr}`,
    html: global.htmlReport,
    text: textParts.join("\n"),
    dates,
    threshold: VARIATION_THRESHOLD,
    excludedPoints: [...EXCLUDED_PV],
    excludedStocksPoints: [...EXCLUDED_STOCKS_PV],
    orderPointVente: pvOrdered,
    reportDate: new Date().toISOString().slice(0,10),
    nonVendusOuStagnantsByPV
  }
}];

