// Mapping explicite portfolio_name -> Point de Vente
const MAP_PDV = {
  CREANCE_DAHRA: 'Dahra',
  CREANCE_KEUR_MASSAR: 'Keur Massar',
  CREANCE_LINGUERE: 'Linguere',
  CREANCE_OUEST_FOIRE: 'O.Foire',
  CREANCE_MBAO: 'Mbao',
  CREANCE_SACRE_COEUR: 'Centre de Découpe Dakar',
  CREANCE_CDD: 'Centre de Découpe Dakar',          // <-- ajouté
  CREANCE_CDB: 'Centre de Découpe Banlieue',       // <-- ajouté
  CREANCE_ABATS: 'Abattage',
};

// Utilitaire : extrait une date (YYYY-MM-DD) depuis différents champs possibles
function parseDateFrom(obj) {
  if (!obj || typeof obj !== 'object') return null;
  const candidates = [obj.date, obj.timestamp, obj.asOf, obj.as_of];
  for (const c of candidates) {
    if (typeof c === 'string' && c.trim()) {
      const d = new Date(c);
      if (!Number.isNaN(d.getTime())) {
        return d.toISOString().slice(0, 10); // YYYY-MM-DD
      }
    }
  }
  return null;
}

// Si une date existe au niveau du flux (premier item), on la mémorise comme valeur par défaut
const flowDate = parseDateFrom(items?.[0]?.json ?? {});

// Extraction souple des portefeuilles selon différentes structures d'entrée
function extractPortfolios(inputItems) {
  const out = [];
  for (const it of inputItems) {
    const j = it.json ?? {};

    if (j.summary && Array.isArray(j.summary.portfolios)) out.push(...j.summary.portfolios);
    if (Array.isArray(j.portfolios)) out.push(...j.portfolios);
    if (Array.isArray(j)) {
      for (const k of j) if (k && typeof k === 'object' && k.portfolio_name) out.push(k);
    }
    if (j.portfolio_name) out.push(j);
  }
  return out;
}

const portfolios = extractPortfolios(items);
const selectedDate = $input.first().json.summary?.date_selected ?? flowDate ?? null;

// Agrégation par PV : plusieurs portefeuilles peuvent pointer sur le même PV
// (ex: CREANCE_SACRE_COEUR et CREANCE_CDD -> Centre de Découpe Dakar)
const aggByPv = new Map();

for (const p of portfolios) {
  const pdv = MAP_PDV[p.portfolio_name];
  if (!pdv) continue; // ignorer les non-mappés

  // difference depuis le JSON, ou fallback: current_balance - previous_balance
  let diff = p.difference;
  if (diff === undefined || diff === null) {
    const cb = p.current_balance;
    const pb = p.previous_balance;
    diff = (typeof cb === 'number' && typeof pb === 'number') ? (cb - pb) : 0;
  }

  // Cumul par PV
  const prev = aggByPv.get(pdv) || { diff: 0, sources: [] };
  prev.diff += Number(diff) || 0;
  prev.sources.push(p.portfolio_name);
  aggByPv.set(pdv, prev);
}

// Construction de la sortie : un item par PV, avec la somme des diffs
const results = [];
for (const [pdv, info] of aggByPv) {
  results.push({
    json: {
      pointVente: pdv,
      differenceCreance: info.diff,
      date: selectedDate,
      // Liste des portefeuilles agrégés (utile pour audit/debug)
      sourcePortfolios: info.sources,
    },
  });
}

return results;

// n8n Function node — Webhook AS-OF-TODAY
// Comportement :
//  - par défaut, le rapport est tiré pour la date du jour (today)
//  - on peut surcharger via le webhook : ?date=DD-MM-YYYY ou ?date=YYYY-MM-DD
//  - on garde les noms de champs (yest, today, date.date-N) pour ne RIEN
//    casser dans les nodes en aval (Get Rec from matix, Split Out, etc.)

function fmt(d) {
  const dd = String(d.getDate()).padStart(2, '0');
  const mm = String(d.getMonth() + 1).padStart(2, '0');
  const yyyy = d.getFullYear();
  return `${dd}-${mm}-${yyyy}`;
}

function parseDateInput(s) {
  if (!s) return null;
  const t = String(s).trim();
  let m;
  if ((m = t.match(/^(\d{4})-(\d{2})-(\d{2})$/)))   return new Date(+m[1], +m[2]-1, +m[3]);
  if ((m = t.match(/^(\d{2})-(\d{2})-(\d{4})$/)))   return new Date(+m[3], +m[2]-1, +m[1]);
  if ((m = t.match(/^(\d{2})\/(\d{2})\/(\d{4})$/))) return new Date(+m[3], +m[2]-1, +m[1]);
  const d = new Date(t);
  return isNaN(d) ? null : d;
}

// Tente de récupérer une date demandée via le webhook
function getRequestedDate() {
  try {
    const wh = $('Webhook').first()?.json || {};
    const candidates = [
      wh?.query?.date,
      wh?.body?.date,
      wh?.params?.date,
      wh?.headers && wh.headers['x-report-date']
    ].filter(Boolean);
    for (const c of candidates) {
      const d = parseDateInput(c);
      if (d) return d;
    }
  } catch (_) { /* webhook non présent */ }
  return null;
}

const requested = getRequestedDate();
const target = requested || new Date();

// Ancrage à minuit local
const start = new Date(target.getFullYear(), target.getMonth(), target.getDate());

// Date principale du rapport = TARGET
// On garde le nom 'yest' pour conserver la compat avec les nodes en aval
// (Get Rec from matix utilise $items('Code0')[0].json.yest comme date du rapport)
const targetStr = fmt(start);

// Pour les multi-dates en aval (Get Rec from matix2 via Split Out) :
//   date-0 = TARGET
//   date-1 = TARGET-1 (hors dimanche)
//   date-2 = TARGET-2 (hors dimanche)
//   date-30 = TARGET-30 (calendaire)
const arr = [targetStr];
const c = new Date(start);
while (arr.length < 3) {
  c.setDate(c.getDate() - 1);
  if (c.getDay() !== 0) arr.push(fmt(c));
}

const minus30 = new Date(start);
minus30.setDate(minus30.getDate() - 30);

const datesObj = {
  "date-0": arr[0],
  "date-1": arr[1],
  "date-2": arr[2],
  "date-30": fmt(minus30),
};

const payload = {
  today: targetStr,
  yest: targetStr,           // = TARGET (today par défaut). Compat aval.
  date: datesObj,
  targetDate: targetStr,
  source: requested ? 'webhook-param' : 'today-default',
  message: `Lancer le rapport AS-OF ${targetStr} (mode webhook)`
};

if (items.length === 0) return [{ json: payload }];
return items.map(item => {
  Object.assign(item.json, payload);
  return item;
});

// n8n Code node — Run Once for All Items
// Entrée: items[0].json contient { period: ..., target: ... }
//        Chaque point de vente peut avoir details[] avec Produit = "Poulet" | "Tablette"
// Sortie: [{ json: { subject, html, text, meta..., sections... } }]

// ======================= Helpers / Config =======================
const PRODUCTS = ["Poulet", "Tablette"];              // familles gérées
const REGION_SET = new Set(["Linguere", "Dahra"]);    // => "Région"
const grp = (pdv) => REGION_SET.has(String(pdv).trim()) ? "Region" : "Dakar";
const n2 = new Intl.NumberFormat("fr-FR",{ minimumFractionDigits:2, maximumFractionDigits:2 });
const n0 = new Intl.NumberFormat("fr-FR");

// ▶ Interrupteur pour masquer/afficher la section "Moyennes" dans le HTML
const SHOW_AVERAGES_HTML = false;

const COLORS = {
  bg:"#F8FAFC", card:"#FFFFFF", ink:"#0F172A", sub:"#475569",
  border:"#E5E7EB", borderLight:"#F1F5F9", thBg:"#F8FAFC", thTxt:"#111827", tdTxt:"#111827",
  okBg:"#E8F5E9", okTxt:"#1B5E20", okBr:"#A5D6A7",
  infoBg:"#EEF2FF", infoTxt:"#1E40AF", infoBr:"#C7D2FE",
  warnBg:"#FFF8E1", warnTxt:"#8D6E00", warnBr:"#FFE082",
  errBg:"#FFEBEE", errTxt:"#B71C1C", errBr:"#EF9A9A",
};

function esc(s){
  return String(s ?? "").replace(/[&<>"']/g, c => (
    { "&":"&amp;","<":"&lt;",">":"&gt;",'"':"&quot;","'":"&#39;" }[c]
  ));
}

function pickNum(o, keys=[]){
  for (const k of keys) {
    const v = k.split(".").reduce((a,c)=> (a && a[c] != null) ? a[c] : undefined, o);
    if (v != null && v !== "" && !isNaN(Number(v))) return Number(v);
  }
  return 0;
}

// Lecture sûre d’une valeur depuis details[] filtrée par produit
function pickFromDetails(row, produit, fieldCandidates){
  if (!Array.isArray(row?.details)) return 0;
  let sum = 0;
  for (const d of row.details) {
    if (String(d?.Produit || d?.produit || d?.Product).trim() !== produit) continue;
    for (const key of fieldCandidates) {
      const v = key.split(".").reduce((a,c)=> (a && a[c] != null) ? a[c] : undefined, d);
      if (v != null && v !== "" && !isNaN(Number(v))) { sum += Number(v); break; }
    }
  }
  return sum;
}

// Normalisation dates (JJ-MM-AAAA / AAAA-MM-JJ / JJ/MM/AAAA)
function normalizeDateStr(s){
  if (!s) return "";
  if (typeof s !== "string") {
    const d = new Date(s); return isNaN(d) ? "" : d.toISOString().slice(0,10);
  }
  const t = s.trim();
  if (/^\d{4}-\d{2}-\d{2}$/.test(t)) return t;
  if (/^\d{2}-\d{2}-\d{4}$/.test(t)) { const [jj,mm,aaaa]=t.split("-"); return `${aaaa}-${mm}-${jj}`; }
  if (/^\d{2}\/\d{2}\/\d{4}$/.test(t)) { const [jj,mm,aaaa]=t.split("/"); return `${aaaa}-${mm}-${jj}`; }
  const d = new Date(t); return isNaN(d) ? t : d.toISOString().slice(0,10);
}

// Cherche un tableau "pointsDeVente" (robuste)
function readBlock(block){
  if (!block) return { meta:{}, rows:[] };
  if (Array.isArray(block)) {
    if (block.length && Array.isArray(block[0]?.pointsDeVente)) {
      const b = block[0];
      return { meta:{ startDate:b.startDate, endDate:b.endDate, date:b.date }, rows:b.pointsDeVente };
    }
    return { meta:{ startDate:block.startDate, endDate:block.endDate, date:block.date }, rows:block };
  }
  if (Array.isArray(block.pointsDeVente)) {
    return { meta:{ startDate:block.startDate, endDate:block.endDate, date:block.date }, rows:block.pointsDeVente };
  }
  return { meta:{}, rows:[] };
}

function classify(sumStock, avgV){
  const ratio = avgV > 0 ? sumStock / avgV : 0;
  let statut = "Adequate";
  if (ratio >= 7)      statut = "OK";
  else if (ratio >= 5) statut = "Adequate";
  else if (ratio >= 3) statut = "Watch";
  else if (ratio >= 2) statut = "Tension";
  else                 statut = "Critical";
  return { ratio, statut };
}

function chip(text, kind="info"){
  const map = {
    info:{bg:COLORS.infoBg,br:COLORS.infoBr,txt:COLORS.infoTxt},
    ok:{bg:COLORS.okBg,br:COLORS.okBr,txt:COLORS.okTxt},
    warn:{bg:COLORS.warnBg,br:COLORS.warnBr,txt:COLORS.warnTxt},
    danger:{bg:COLORS.errBg,br:COLORS.errBr,txt:COLORS.errTxt},
  }[kind] || {bg:"#EEE", br:"#DDD", txt:"#333"};
  return `<span style="display:inline-block;padding:2px 8px;border:1px solid ${map.br};border-radius:999px;background:${map.bg};color:${map.txt};font-size:12px;line-height:18px;">${esc(text)}</span>`;
}
function chipByStatus(statut){
  const k = (statut === "OK") ? "ok"
        : (statut === "Adequate") ? "info"
        : (statut === "Watch" || statut === "Tension") ? "warn"
        : "danger";
  return chip(statut, k);
}
function statusKind(statut){
  return (statut === "OK") ? "ok"
       : (statut === "Adequate") ? "info"
       : (statut === "Watch" || statut === "Tension") ? "warn"
       : "danger"; // Critical / autres
}
function statusTextColor(statut){
  const kind = statusKind(statut);
  return (kind === "ok") ? COLORS.okTxt
       : (kind === "info") ? COLORS.infoTxt
       : (kind === "warn") ? COLORS.warnTxt
       : COLORS.errTxt;
}
function daysToDeliver(ratio){
  const r = Number.isFinite(+ratio) ? Math.floor(+ratio) : 0;
  return Math.max(0, r);
}
function daysLabel(d){
  return `${d} ${d>1 ? "jours" : "jour"}`;
}

// ======================= Agrégation par PRODUIT =======================
function aggregateByProduct(periodRows, targetRows, produit){
  // Agg périodes (somme ventes & jours) par groupe
  const agg = { Region:{ ventes:0, days:0 }, Dakar:{ ventes:0, days:0 } };

  for (const r of periodRows) {
    const pdv = r.PointDeVente ?? r.pointVente ?? r.pdv;
    const g = grp(pdv);

    // VentesThéoriques filtrées par produit (détails), sinon fallback global
    let vendas = 0;
    if (Array.isArray(r?.details)) {
      vendas += pickFromDetails(r, produit, ["VentesTheoriques","ventesTheoriques"]);
    } else {
      // Fallback si pas de détail produit
      vendas += pickNum(r, ["VentesTheoriques","details.0.VentesTheoriques","resume.0.VentesTheoriques"]);
    }

    // Nombre de jours (si disponible par produit, sinon global)
    let days = 0;
    if (Array.isArray(r?.details)) {
      days += pickFromDetails(r, produit, ["AvgVentesTheoriqueDayCount","DaysCount","NbJours"]);
    }
    if (days === 0) {
      days += pickNum(r, ["AvgVentesTheoriqueDayCount","details.0.AvgVentesTheoriqueDayCount","resume.0.AvgVentesTheoriqueDayCount","DaysCount","NbJours"]);
    }

    agg[g].ventes += vendas;
    agg[g].days   += days;
  }

  const avg = {
    Region: agg.Region.days>0 ? agg.Region.ventes/agg.Region.days : 0,
    Dakar:  agg.Dakar.days>0  ? agg.Dakar.ventes/agg.Dakar.days   : 0,
  };

  // Stocks du soir ciblés par produit
  const stock = { Region:0, Dakar:0 };
  for (const r of targetRows) {
    const pdv = r.PointDeVente ?? r.pointVente ?? r.pdv;
    const g = grp(pdv);
    let ss = 0;
    if (Array.isArray(r?.details)) {
      ss += pickFromDetails(r, produit, ["StockSoir","stockSoir"]);
    } else {
      ss += pickNum(r, ["StockSoir","details.0.StockSoir","resume.0.StockSoir"]);
    }
    stock[g] += ss;
  }

  const cls = {
    Region: classify(stock.Region, avg.Region),
    Dakar:  classify(stock.Dakar,  avg.Dakar),
  };

  return { agg, avg, stock, cls };
}

// ======================= HTML builders =======================
const tableBase = "width:100%;border-collapse:collapse;margin:8px 0;";
const thBase = `text-align:left;padding:8px;border-bottom:1px solid ${COLORS.border};background:${COLORS.thBg};font-weight:600;font-size:14px;color:${COLORS.thTxt};`;
const tdBase = `padding:8px;border-bottom:1px solid ${COLORS.borderLight};font-size:14px;color:${COLORS.tdTxt};`;

function buildAveragesTable(label, avg, agg){
  // (la fonction reste disponible, mais ne sera pas appelée si SHOW_AVERAGES_HTML=false)
  return `
  <div style="margin:12px 0 4px 0;font-weight:800;color:${COLORS.ink};font-size:16px;">
    ${esc(label)} — Moyennes de ventes / jour (période)
  </div>
  <table style="${tableBase}">
    <thead>
      <tr>
        <th style="${thBase};width:22%">Groupe</th>
        <th style="${thBase};width:18%;text-align:right;">Moyenne / jour</th>
        <th style="${thBase};width:30%;text-align:right;">Somme ventes</th>
        <th style="${thBase};width:30%;text-align:right;">Somme jours</th>
      </tr>
    </thead>
    <tbody>
      <tr>
        <td style="${tdBase}"><strong>Région</strong></td>
        <td style="${tdBase};text-align:right;">${n2.format(avg.Region)}</td>
        <td style="${tdBase};text-align:right;">${n0.format(agg.Region.ventes)}</td>
        <td style="${tdBase};text-align:right;">${n0.format(agg.Region.days)}</td>
      </tr>
      <tr>
        <td style="${tdBase}"><strong>Dakar</strong></td>
        <td style="${tdBase};text-align:right;">${n2.format(avg.Dakar)}</td>
        <td style="${tdBase};text-align:right;">${n0.format(agg.Dakar.ventes)}</td>
        <td style="${tdBase};text-align:right;">${n0.format(agg.Dakar.days)}</td>
      </tr>
    </tbody>
  </table>`;
}

