/* ---------------- Helpers ---------------- */
function formatCurrency(v){ const n=Number(v)||0; return n.toLocaleString('fr-FR')+' FCFA'; }
function formatNumber(v){
  const n=Number(v); if(!Number.isFinite(n)) return '0';
  const isInt = Math.abs(n - Math.round(n)) < 1e-9;
  return n.toLocaleString('fr-FR',{minimumFractionDigits:isInt?0:2, maximumFractionDigits:isInt?0:2});
}
function normalizeDateStr(s){
  if (!s) return '';
  if (s instanceof Date && !isNaN(s)) return s.toISOString().slice(0,10);
  if (typeof s!=='string'){ const d=new Date(s); return isNaN(d)?'':d.toISOString().slice(0,10); }
  const t=s.trim();
  if (/^\d{4}-\d{2}-\d{2}T/.test(t)) return t.slice(0,10);
  if (/^\d{4}-\d{2}-\d{2}$/.test(t)) return t;
  if (/^\d{2}-\d{2}-\d{4}$/.test(t)){ const [jj,mm,aa]=t.split('-'); return `${aa}-${mm}-${jj}`; }
  if (/^\d{2}\/\d{2}\/\d{4}$/.test(t)){ const [jj,mm,aa]=t.split('/'); return `${aa}-${mm}-${jj}`; }
  const d=new Date(t); return isNaN(d)?'':d.toISOString().slice(0,10);
}
function esc(x){ return String(x??'').replace(/[&<>"']/g,c=>({ '&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c])); }
function safeItems(name){ try{ return (typeof $items==='function')?($items(name)||[]):[] }catch(_){ return [] } }
function normalizeSpecies(s){
  const t = String(s||'').normalize('NFD').replace(/[\u0300-\u036f]/g,'').trim().toLowerCase();
  return (t==='veau') ? 'veau' : 'boeuf'; // défaut = boeuf
}

