const BADGE_BASE = 'display:inline-block;padding:2px 8px;border-radius:999px;font-size:12px;line-height:18px;color:#fff;';
const BADGE_COLORS = { success:'#16a34a', warning:'#f59e0b', danger:'#dc2626' };

function badge(label, tone){
  const bg = BADGE_COLORS[tone] || '#6b7280';
  return `<span class="badge bg-${tone}" style="${BADGE_BASE};background:${bg};">${esc(label)}</span>`;
}

function classifyPrice(species, prixKg){
  const v = Number(prixKg)||0;
  if (species==='boeuf'){
    if (v <= 3200) return {label:'Bon', tone:'success'};
    if (v >= 3201 && v <= 3350) return {label:'Acceptable', tone:'warning'};
    if (v > 3350) return {label:'Mauvais', tone:'danger'};
  } else { // veau
    if (v <= 3400) return {label:'Bon', tone:'success'};
    if (v >= 3401 && v <= 3550) return {label:'Acceptable', tone:'warning'};
    if (v > 3550) return {label:'Mauvais', tone:'danger'};
  }
  return null;
}
function statusBadge(species, prixKg){
  const cls = classifyPrice(species, prixKg);
  return cls ? badge(cls.label, cls.tone) : 'N.A';
}
