/* --------------- Charger données matix1 (prix bœuf/veau) ---------------- */
const MATIX_NODE = 'Get Boeuf prix from matix1';

function normalizeMatixPayload(j){
  if (!j) return null;
  if (typeof j==='string'){ try{ j=JSON.parse(j);}catch{} }
  if (j?.data) j=j.data;
  if (j?.achats || j?.totals || j?.week || j?.month){
    return {
      achats: Array.isArray(j.achats)? j.achats : [],
      totals: j.totals || null,
      week:   j.week   || null,
      month:  j.month  || null,
    };
  }
  if (Array.isArray(j)){
    for (const r of j){ const p=normalizeMatixPayload(r); if (p) return p; }
  }
  return null;
}
function collectMatixPurchases(){
  const out={ achats:[], totals:null, week:null, month:null };
  // 1) items directs
  for (const it of items){
    const pack=normalizeMatixPayload(it?.json); if (!pack) continue;
    out.totals ||= pack.totals; out.week ||= pack.week; out.month ||= pack.month;
    out.achats.push(...pack.achats);
  }
  // 2) via nœud matix
  for (const it of safeItems(MATIX_NODE)){
    const pack=normalizeMatixPayload(it?.json); if (!pack) continue;
    out.totals ||= pack.totals; out.week ||= pack.week; out.month ||= pack.month;
    out.achats.push(...pack.achats);
  }
  // dédup + tri
  const seen=new Set();
  out.achats = out.achats.filter(a=>{
    const key=`${a?.id||''}|${a?.date||''}|${a?.prix||''}|${(a?.bete||'').toLowerCase()}`;
    if (seen.has(key)) return false; seen.add(key); return true;
  }).sort((a,b)=>{
    const da=normalizeDateStr(a?.date), db=normalizeDateStr(b?.date);
    if (da!==db) return da.localeCompare(db);
    return (a?.id||0)-(b?.id||0);
  });
  return out;
}

