  return n.toString().replace(/\B(?=(\d{3})+(?!\d))/g, '.'); // 75.000
};
const fmtPct = (v) => `${(Number.isFinite(v) ? v : 0).toFixed(2)} %`;

function statusFromPct(pct) {
  if (!Number.isFinite(pct)) return {emoji: '⚪', label: 'N.A', color: '#6b7280'};
  const ap = Math.abs(pct);
  if (ap <= 10) return {emoji: '🟢', label: 'Vert',  color: '#16a34a'};
  if (ap <= 20) return {emoji: '🟡', label: 'Jaune', color: '#d97706'};
  return {emoji: '🔴', label: 'Rouge', color: '#dc2626'};
}

// ----- En-têtes (Pré-commande avant Estimation) -----
const headers = [
  'Date',
  'Point de Vente',
  'Catégorie',
  'Pré-commande',
  'Estimation',
  'Ventes théo.',
  'Différence',
  'Différence (%)',
  'Status',
  'Commentaire',
];

// ----- Construction des lignes à partir de la data -----
let dateKey = '';
const detailRows = [];

if (dataRoot && Object.keys(dataRoot).length > 0) {
  const dateKeys = Object.keys(dataRoot);
  dateKey = dateKeys[0];
  const pdvBlock = dataRoot[dateKey] || {};

  for (const [pdv, categories] of Object.entries(pdvBlock)) {
    for (const [categorie, c] of Object.entries(categories || {})) {
      const hasEstimation = !(c.estimation === undefined || c.estimation === null || String(c.estimation).trim() === '');
      const estimation  = hasEstimation ? toNumber(c.estimation) : null;
      const precommande = toNumber(c.precommande);
      const ventesTheo  = toNumber(c.ventes_theoriques);

      const difference  = (c.difference !== undefined && c.difference !== null)
        ? toNumber(c.difference)
        : (ventesTheo - (hasEstimation ? estimation : 0) - precommande);

      const differencePct = (hasEstimation && estimation !== 0) ? (difference / estimation) * 100 : NaN;
      const st = statusFromPct(differencePct);

      detailRows.push({
        date: dateKey,
        pointDeVente: pdv,
        categorie,
        precommande,
        estimation,           // null => affichage "pas d’estimation !"
        hasEstimation,
        ventesTheo,
        difference,
        differencePct,
        status: st,
        commentaire: (c.commentaire ?? '-'),
      });
    }
  }

  // tri optionnel
  detailRows.sort((a, b) =>
    a.date.localeCompare(b.date, 'fr') ||
    a.pointDeVente.localeCompare(b.pointDeVente, 'fr') ||
    a.categorie.localeCompare(b.categorie, 'fr')
  );
}

// ----- HTML -----
let html = `
<table style="width:100%;border-collapse:collapse;font-family:Inter,Arial,sans-serif;font-size:14px">
  <thead>
