      ${headers.map(h => `<th style="padding:10px 8px;border-bottom:1px solid #e5e7eb">${h}</th>`).join('')}
    </tr>
  </thead>
  <tbody>
`;

if (detailRows.length === 0) {
  // AUCUNE DONNÉE : afficher une ligne unique dans le tbody
  html += `
    <tr>
      <td colspan="${headers.length}" style="padding:14px 10px;color:#6b7280;text-align:center;font-style:italic;background:#fbfbfd;border-bottom:1px solid #f3f4f6">
        ${PLACEHOLDER_TEXT}
      </td>
    </tr>
  `;
} else {
  for (const r of detailRows) {
    const pctText = Number.isFinite(r.differencePct) ? fmtPct(r.differencePct) : 'N.A';
    const diffColor = r.difference >= 0 ? '#16a34a' : '#dc2626';
    const estCell = r.hasEstimation ? fmtIntDot(r.estimation) : `<span style="font-weight:600">${PLACEHOLDER_TEXT}</span>`;

    html += `
      <tr style="border-bottom:1px solid #f3f4f6">
        <td style="padding:10px 8px;color:#111827">${r.date}</td>
        <td style="padding:10px 8px;color:#111827">${r.pointDeVente}</td>
        <td style="padding:10px 8px;color:#111827">${r.categorie}</td>
        <td style="padding:10px 8px;color:#111827;font-weight:600">${fmtIntDot(r.precommande)}</td>
        <td style="padding:10px 8px;color:#111827;font-weight:600">${estCell}</td>
        <td style="padding:10px 8px;color:#111827">${fmtIntDot(r.ventesTheo)}</td>
        <td style="padding:10px 8px;color:${diffColor};font-weight:600">${fmtIntDot(r.difference)}</td>
        <td style="padding:10px 8px;color:${r.status.color};font-weight:600">${pctText}</td>
        <td style="padding:10px 8px;color:${r.status.color};font-weight:600">
          <span style="display:inline-block;width:10px;height:10px;border-radius:50%;background:${r.status.color};vertical-align:middle;margin-right:6px"></span>
          ${r.status.label}
        </td>
        <td style="padding:10px 8px;color:#6b7280">${String(r.commentaire || '-')}</td>
      </tr>
    `;
  }
}
html += '</tbody></table>';

// ----- TEXTE (monospacé) -----
const table = [headers];
if (detailRows.length === 0) {
  // Une seule ligne avec placeholder (alignée sous la 1ʳᵉ colonne)
  const row = new Array(headers.length).fill('');
  row[0] = PLACEHOLDER_TEXT;
  table.push(row);
} else {
  for (const r of detailRows) {
    table.push([
      r.date,
      r.pointDeVente,
      r.categorie,
      fmtIntDot(r.precommande),
      r.hasEstimation ? fmtIntDot(r.estimation) : PLACEHOLDER_TEXT,
      fmtIntDot(r.ventesTheo),
      fmtIntDot(r.difference),
      Number.isFinite(r.differencePct) ? fmtPct(r.differencePct) : 'N.A',
      r.status.emoji,
      String(r.commentaire || '-'),
    ]);
  }
}
const colWidths = headers.map((_, i) =>
  Math.max(...table.map(row => String(row[i]).length))
);
let text = '';
for (const row of table) {
  text += row.map((cell, i) => String(cell).padEnd(colWidths[i] + 2, ' ')).join('') + '\n';
}

return [{
  json: {
    date: dateKey || '',
