// n8n Code node
// Input : items[0].json.details (object) OR items[0].json[0].details (array wrapper)
// Output: items[0].json.output_html (string)

function escapeHtml(s) {
  return String(s ?? '')
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;');
}

function round2(n) {
  const v = Number(n);
  if (!isFinite(v)) return '0.00';
  return v.toFixed(2);
}

function formatFCFA(n) {
  const v = Number(n);
  const intVal = isFinite(v) ? Math.round(v) : 0;
  const s = String(intVal).replace(/\B(?=(\d{3})+(?!\d))/g, ' ');
  return `${s} FCFA`;
}

function computeDiffPct(theo, reel) {
  const t = Number(theo);
  const r = Number(reel);
  const T = isFinite(t) ? t : 0;
  const R = isFinite(r) ? r : 0;
  const denom = Math.max(1, T);
  const diff = T - R;
  return (Math.abs(diff) / denom) * 100;
}

function computeNiveauFromDiffPct(diffPct) {
  const v = Number(diffPct);
  if (!isFinite(v)) return 'OK';
  if (v > 10) return 'Anomalie';
  if (v > 5) return 'À surveiller';
  return 'OK';
}

function getBadge(label) {
  const l = (label || '').toLowerCase();
  let bg = '#eaf7ee', bd = '#bfe6ca', fg = '#0c6b2d';
  if (l.includes('anomalie')) { bg = '#ffe3e3'; bd = '#ffb3b3'; fg = '#8a0000'; }
  else if (l.includes('surveiller')) { bg = '#fff3d6'; bd = '#ffd79a'; fg = '#8a5a00'; }

  return `<span style="display:inline-block;padding:2px 10px;border-radius:999px;font-weight:700;font-size:12px;border:1px solid ${bd};background:${bg};color:${fg};white-space:nowrap;">
    ${escapeHtml(label)}
  </span>`;
}

function getDetailsFromItem(itemJson) {
  if (itemJson?.details && typeof itemJson.details === 'object') return itemJson.details;
  if (Array.isArray(itemJson) && itemJson[0]?.details) return itemJson[0].details;
  return null;
}

/** ✅ NOUVEAU: agrège Boeuf+Veau+Mergez+Viande hachée */
function sumFam(pvObj, famNames, field) {
  return famNames.reduce((acc, fam) => acc + Number(pvObj?.[fam]?.[field] ?? 0), 0);
}

function buildSyntheseRows(details) {
  const excluded = new Set(['Abattage', 'Chambre froide', 'Linguere', 'Dahra']);
  const pvNames = Object.keys(details).filter(pv => !excluded.has(pv));

  const rows = [];
  for (const pv of pvNames) {
    const pvObj = details[pv] || {};

    // ✅ Boeuf+Veau (+ Mergez + Viande hachée)
    const BV_EXTRA = ['Boeuf', 'Veau', 'Mergez', 'Viande hachée'];
    const theoBV = sumFam(pvObj, BV_EXTRA, 'ventesTheoriquesNombre');
    const reelBV = sumFam(pvObj, BV_EXTRA, 'ventesNombreAjustePack');

    const ecartBV = theoBV - reelBV;
    const diffPctBV = computeDiffPct(theoBV, reelBV);
    const nivBV = computeNiveauFromDiffPct(diffPctBV);

    rows.push({ pv, fam: 'Boeuf+Veau', theo: theoBV, reel: reelBV, ecart: ecartBV, diffPct: diffPctBV, niveau: nivBV });

    // Agneau / Poulet / Poisson
    for (const fam of ['Agneau', 'Poulet', 'Poisson']) {
      const x = pvObj[fam] || {};
      const theo = x.ventesTheoriquesNombre || 0;
      const reel = x.ventesNombreAjustePack || 0;
      const ecart = theo - reel;
      const diffPct = computeDiffPct(theo, reel);
      const niveau = computeNiveauFromDiffPct(diffPct);

      rows.push({ pv, fam, theo, reel, ecart, diffPct, niveau });
    }
  }
  return rows;
}

function buildSyntheseHTML(rows) {
  const headerCells = ['Point de vente','Famille','Théorique','Réel ajusté','Écart','diffPct','Niveau']
    .map(x => `<th style="border:1px solid #e6e6e6;padding:8px;background:#f7f7f7;text-align:left">${escapeHtml(x)}</th>`)
    .join('');

  const body = rows.map(r => {
    const isWatch = r.niveau === 'À surveiller';
    const trStyle = isWatch ? 'font-weight:700;color:#b00020;' : '';

    return `
      <tr style="${trStyle}">
        <td style="border:1px solid #e6e6e6;padding:8px">${escapeHtml(r.pv)}</td>
        <td style="border:1px solid #e6e6e6;padding:8px">${escapeHtml(r.fam)}</td>
        <td style="border:1px solid #e6e6e6;padding:8px">${round2(r.theo)}</td>
        <td style="border:1px solid #e6e6e6;padding:8px">${round2(r.reel)}</td>
        <td style="border:1px solid #e6e6e6;padding:8px">${round2(r.ecart)}</td>
        <td style="border:1px solid #e6e6e6;padding:8px">${round2(r.diffPct)}%</td>
        <td style="border:1px solid #e6e6e6;padding:8px">${getBadge(r.niveau)}</td>
      </tr>
    `;
  }).join('');

  return `
  <table style="width:100%;border-collapse:collapse;font-size:13px">
    <thead><tr>${headerCells}</tr></thead>
    <tbody>${body}</tbody>
  </table>`;
}

function buildAbattoirFromDetails(details) {
  const abat = details['Abattage'] || {};
  const abatsValeur = Number(abat?.Abats?.ventesValeur ?? 0);
  const peauxValeur = Number(abat?.Peaux?.ventesValeur ?? 0);
  const ventesAbatsPeaux = abatsValeur + peauxValeur;

  const boeufKg = Number(abat?.Boeuf?.ventesTheoriquesNombre ?? 0);
  const veauKg  = Number(abat?.Veau?.ventesTheoriquesNombre ?? 0);

  return { ventesAbatsPeaux, boeufKg, veauKg };
}

function buildAbattoirTable(a) {
  return `
  <table style="width:100%;border-collapse:collapse;font-size:13px;margin-top:10px">
    <thead>
      <tr>
        ${['Source','Indicateur','Valeur']
          .map(x => `<th style="border:1px solid #e6e6e6;padding:8px;background:#f7f7f7;text-align:left">${escapeHtml(x)}</th>`)
          .join('')}
      </tr>
    </thead>
    <tbody>
      <tr>
        <td style="border:1px solid #e6e6e6;padding:8px"><b>Abattage</b></td>
        <td style="border:1px solid #e6e6e6;padding:8px">Ventes abats + peaux</td>
        <td style="border:1px solid #e6e6e6;padding:8px">${escapeHtml(formatFCFA(a.ventesAbatsPeaux))}</td>
      </tr>
      <tr>
        <td style="border:1px solid #e6e6e6;padding:8px"><b>Abattage</b></td>
        <td style="border:1px solid #e6e6e6;padding:8px">Pertes de poids – Boeuf</td>
        <td style="border:1px solid #e6e6e6;padding:8px">${round2(a.boeufKg)} kg</td>
      </tr>
      <tr>
        <td style="border:1px solid #e6e6e6;padding:8px"><b>Abattage</b></td>
        <td style="border:1px solid #e6e6e6;padding:8px">Pertes de poids – Veau</td>
        <td style="border:1px solid #e6e6e6;padding:8px">${round2(a.veauKg)} kg</td>
      </tr>
    </tbody>
  </table>`;
}

// ---------------- MAIN ----------------
const itemJson = items[0]?.json;
const details = getDetailsFromItem(itemJson);

if (!details) {
  return [{
    json: {
      ...itemJson,
      output_html: `<div style="font-family:Arial;color:#8a0000;font-weight:700">
        Champ "details" introuvable dans le JSON d'entrée.
      </div>`
    }
  }];
}

const synthRows = buildSyntheseRows(details);
const synthHtml = buildSyntheseHTML(synthRows);

const abattoir = buildAbattoirFromDetails(details);
const abattoirHtml = buildAbattoirTable(abattoir);

const output_html = `
<div style="font-family:Arial,Helvetica,sans-serif;max-width:980px;color:#111">
  <div style="font-size:16px;font-weight:700;margin:0 0 10px">Synthèse finale – Tableau</div>
  ${synthHtml}

  <div style="font-size:14px;font-weight:700;margin:14px 0 8px">Abattoir</div>
  ${abattoirHtml}
</div>
`;

return [{
  json: {
    ...itemJson,
    output_html
  }
}];

/**
 * n8n Code node (JavaScript)
 * Objectif : construire un JSON unique qui regroupe tes blocs HTML/TEXT
 * (VENTE, ESTIMATION, VOLAILLE, etc.) pour l’envoyer ensuite à ton agent.
 *
 * À utiliser dans un Code node placé APRÈS les nodes cités.
 */

const vente = $('Rapport').item.json.text ?? '';
const estimation = $('Format estimation').item.json.text ?? '';
const volaille = $('Format Volaille').item.json.text ?? '';
const perfAchatBovin = $('Perf Achat Format').item.json.text ?? '';
const prixBoeuf = $('Boeuf prix').item.json.text ?? '';
const depenses = $('Format Depenses').item.json.text ?? '';
const chambreFroide = $('Get Chambre froide').item.json.text ?? '';
const dateDebutMois = $('mlc').item.json.date ?? '';
const ecartStockVsVentesMois = $json.details ?? '';

return [
  {
    json: {
      sections: {
        VENTE: vente,
        ESTIMATION: estimation,
        VOLAILLE: volaille,
        "PERFORMANCE ACHAT BOVIN": perfAchatBovin,
        "PRIX BOEUF": prixBoeuf,
        DEPENSES: depenses,
        "CHAMBRE FROIDE": chambreFroide,
        [`ECART STOCK VS VENTES DU MOIS (DEBUT DE MOIS - ${dateDebutMois})`]:
          ecartStockVsVentesMois,
      },
    },
  },
];

/**
 * n8n Code node (JavaScript)
 * Version avec extraction du Prix/kg BOEUF
 */

const items = $input.all();
if (!items.length) return [];

const sections = items[0].json.sections;
const out = {
  date: "",
  ventes: {},
  achats_boeuf: {
    details_jour: [],
    alerte_prix: false
  },
  alerts_pv: [],
  stock_alerts: [],
  abattoir: {}
};

// --- 1. EXTRACTION PRIX BOEUF (Nouveau) ---
const htmlPrix = sections["PRIX BOEUF"] || "";

// Extraction du "Prix/kg sans abats" dans le tableau Détails
// On cherche les lignes du tableau qui ne sont pas vides
const achatRows = htmlPrix.matchAll(/<tr><td.*?>(.*?)<\/td><td.*?>(.*?)<\/td><td.*?>(.*?)<\/td><td.*?>(.*?)<\/td><td.*?>(.*?)<\/td><td.*?>(.*?)<\/td>/g);

for (const match of achatRows) {
  const [_, date, bete, prixTotal, abats, kg, prixKg] = match;
  if (bete !== "—" && bete.toLowerCase().includes("boeuf")) {
    out.achats_boeuf.details_jour.push({
      bete: bete.trim(),
      kg: cleanValue(kg),
      prix_kg_sans_abats: cleanValue(prixKg)
    });
  }
}

// Détection de l'alerte prix (Statut "Mauvais" en rouge)
if (htmlPrix.includes("background:#dc2626") && htmlPrix.includes("Mauvais")) {
  out.achats_boeuf.alerte_prix = true;
}

// --- 2. RESTES DES EXTRACTIONS (Vente, Stock, Abattoir) ---
const htmlVente = sections["VENTE"] || "";
const dateMatch = htmlVente.match(/Date d'analyse : <strong>(.*?)<\/strong>/);
out.date = dateMatch ? dateMatch[1] : "";

// Extraction Ventes
const salesMatch = htmlVente.match(/Vente du jour \(saisies\) :.*?color:#1E8449.*?>(.*?) FCFA/s);
out.ventes.jour = salesMatch ? cleanValue(salesMatch[1]) : 0;

// Extraction Abattoir
const htmlStock = sections["ECART STOCK VS VENTES DU MOIS (DEBUT DE MOIS - 2026-02-05)"] || "";
const abatsPeauxMatch = htmlStock.match(/Ventes abats \+ peaux.*?>(.*?) FCFA/s);
out.abattoir.abats_peaux = abatsPeauxMatch ? abatsPeauxMatch[1].trim() : "0 FCFA";

// Nettoyage final des valeurs numériques
function cleanValue(str) {
  if (!str) return 0;
  return parseFloat(str.replace(/\s/g, '').replace(/&nbsp;/g, '').replace(/[^0-9.-]+/g, '')) || 0;
}

return [{ json: out }];

